/**
 * AI 工具面板
 * 包含：智能续写、定向扩写、逻辑校验、提取事实、AI重写、AI润色、大纲生成、风格迁移
 */

import { useState } from 'react'
import {
  Button,
  Space,
  Card,
  Input,
  message,
  Spin,
  Modal,
  Select,
  Divider,
  Tooltip,
  Tabs,
  Alert,
} from 'antd'
import {
  EditOutlined,
  ExpandOutlined,
  CheckCircleOutlined,
  ThunderboltOutlined,
  SaveOutlined,
  SyncOutlined,
  BulbOutlined,
  BgColorsOutlined,
  ProfileOutlined,
} from '@ant-design/icons'
import aiModelService from '../services/aiModels'
import factExtractor, { ExtractedFact } from '../services/factExtractor'

const { TextArea } = Input

interface AIToolsPanelProps {
  chapterContent: string
  chapterPath: string | null
  onInsertText: (text: string) => void
}

const STYLE_OPTIONS = [
  { value: '金庸', label: '金庸（武侠古典）' },
  { value: '猫腻', label: '猫腻（文笔华丽）' },
  { value: '烽火戏诸侯', label: '烽火戏诸侯（热血燃系）' },
  { value: '乌山居', label: '乌山居（简洁流畅）' },
  { value: '辰东', label: '辰东（宏大壮阔）' },
  { value: '土豆', label: '土豆（小白文爽文）' },
]

const AIToolsPanel = ({ chapterContent, chapterPath, onInsertText }: AIToolsPanelProps) => {
  const [generating, setGenerating] = useState(false)
  const [result, setResult] = useState('')
  const [prompt, setPrompt] = useState('')
  const [extractedFacts, setExtractedFacts] = useState<ExtractedFact[]>([])
  const [activeTool, setActiveTool] = useState<string>('continue')

  // 智能续写
  const handleContinue = async () => {
    if (!chapterContent) {
      message.warning('请先选择章节并编写内容')
      return
    }
    setActiveTool('continue')
    setGenerating(true)
    setResult('')

    try {
      const context = chapterContent.slice(-800)
      const fullPrompt = `请继续写下面的小说内容，风格保持一致，衔接自然：

${context}

续写内容（请直接输出续写文本，不需要加标题）：`

      await aiModelService.stream(
        'creative',
        fullPrompt,
        (chunk) => setResult(prev => prev + chunk),
        (error) => message.error(`续写失败：${error}`)
      )
    } catch (error) {
      message.error('续写失败')
    } finally {
      setGenerating(false)
    }
  }

  // 定向扩写
  const handleExpand = async () => {
    if (!prompt) {
      message.warning('请输入扩写要求')
      return
    }
    if (!chapterContent) {
      message.warning('请先选择章节')
      return
    }
    setActiveTool('expand')
    setGenerating(true)
    setResult('')

    try {
      const fullPrompt = `请根据以下要求扩写小说内容。要求：${prompt}

当前章节上下文：
${chapterContent.slice(-1200)}

扩写后的内容（请直接输出扩写文本）：`

      await aiModelService.stream(
        'creative',
        fullPrompt,
        (chunk) => setResult(prev => prev + chunk),
        (error) => message.error(`扩写失败：${error}`)
      )
    } catch (error) {
      message.error('扩写失败')
    } finally {
      setGenerating(false)
    }
  }

  // 逻辑校验
  const handleCheck = async () => {
    if (!chapterContent) {
      message.warning('请先选择章节')
      return
    }
    setActiveTool('check')
    setGenerating(true)
    setResult('')

    try {
      const checkResult = await aiModelService.call(
        'logic',
        chapterContent,
        {
          systemPrompt: `请检查以下小说章节内容的逻辑一致性，找出矛盾点、战力崩坏、情节不合理的地方，给出修改建议。请使用清晰的格式输出检查结果。`
        }
      )

      if (checkResult.success && checkResult.content) {
        setResult(checkResult.content)
      } else {
        message.error(checkResult.error || '校验失败')
      }
    } catch (error) {
      message.error('逻辑校验失败')
    } finally {
      setGenerating(false)
    }
  }

  // 提取事实
  const handleExtract = async () => {
    if (!chapterContent || !chapterPath) {
      message.warning('请先选择章节')
      return
    }
    setActiveTool('extract')
    setGenerating(true)
    setResult('')

    try {
      const chapterMatch = chapterPath.match(/第(\d+)章/)
      const chapterNumber = chapterMatch ? parseInt(chapterMatch[1]) : 1

      const facts = await factExtractor.extract(chapterContent, chapterNumber)
      setExtractedFacts(facts)

      if (facts.length === 0) {
        setResult('未提取到任何事实')
        return
      }

      let output = `提取到 ${facts.length} 条事实：\n\n`
      facts.forEach((fact, index) => {
        output += `${index + 1}. [${fact.type}] ${fact.subject}${fact.object ? ' → ' + fact.object : ''}\n`
        output += `   ${fact.content} (置信度: ${(fact.confidence * 100).toFixed(0)}%)\n\n`
      })

      output += `\n点击「保存到台账」将以上事实追加写入 facts YAML 文件。`
      setResult(output)
    } catch (error) {
      message.error('事实提取失败')
    } finally {
      setGenerating(false)
    }
  }

  // 保存提取的事实到 facts 台账
  const handleSaveFacts = async () => {
    if (extractedFacts.length === 0) return
    setGenerating(true)
    try {
      const chapterMatch = chapterPath?.match(/第(\d+)章/)
      const chapterNumber = chapterMatch ? parseInt(chapterMatch[1]) : 1
      const saved = await factExtractor.extractAndSave(chapterContent, chapterNumber)
      if (saved.length > 0) {
        message.success(`已保存 ${saved.length} 条事实到台账`)
        setResult('')
        setExtractedFacts([])
      } else {
        message.error('保存失败')
      }
    } catch (error) {
      message.error('保存失败')
    } finally {
      setGenerating(false)
    }
  }

  // ── 新增功能 ──────────────────────────────────────────────────────────────

  // AI 重写
  const [rewriteMode, setRewriteMode] = useState<'chapter' | 'paragraph'>('chapter')
  const [rewritePrompt, setRewritePrompt] = useState('')

  const handleRewrite = async () => {
    if (!chapterContent) {
      message.warning('请先选择章节')
      return
    }
    setActiveTool('rewrite')
    setGenerating(true)
    setResult('')

    try {
      let rewritePromptText = rewritePrompt || '请重新组织语言，保持相同的情节和主题'
      const modeText = rewriteMode === 'chapter' ? '整章' : '所选段落'

      if (rewriteMode === 'paragraph') {
        // 取最后一段（如果用户只选了某段的话，用最后500字作为示例）
        const para = chapterContent.slice(-500)
        const fullPrompt = `请重写以下小说段落，保持情节和主题不变，但改善文笔和叙事：

原文：
${para}

重写要求：${rewritePromptText}

重写后的内容（直接输出）：`

        await aiModelService.stream(
          'creative',
          fullPrompt,
          (chunk) => setResult(prev => prev + chunk),
          (error) => message.error(`重写失败：${error}`)
        )
      } else {
        const fullPrompt = `请重写以下小说章节，保持情节和主题不变，但改善文笔和叙事：

原文：
${chapterContent.slice(-2000)}

重写要求：${rewritePromptText}

重写后的内容（直接输出）：`

        await aiModelService.stream(
          'creative',
          fullPrompt,
          (chunk) => setResult(prev => prev + chunk),
          (error) => message.error(`重写失败：${error}`)
        )
      }
    } catch (error) {
      message.error('重写失败')
    } finally {
      setGenerating(false)
    }
  }

  // AI 润色
  const handlePolish = async () => {
    if (!chapterContent) {
      message.warning('请先选择章节')
      return
    }
    setActiveTool('polish')
    setGenerating(true)
    setResult('')

    try {
      const fullPrompt = `请对以下小说内容进行文笔润色，改善表达流畅度、精简冗余、提升文字质感，但不改变原意和情节：

原文：
${chapterContent.slice(-1500)}

润色后的内容（直接输出，不要加说明）：`

      await aiModelService.stream(
        'creative',
        fullPrompt,
        (chunk) => setResult(prev => prev + chunk),
        (error) => message.error(`润色失败：${error}`)
      )
    } catch (error) {
      message.error('润色失败')
    } finally {
      setGenerating(false)
    }
  }

  // 大纲生成
  const [outlineMode, setOutlineMode] = useState<'chapter' | 'full'>('chapter')

  const handleGenerateOutline = async () => {
    if (!chapterContent) {
      message.warning('请先选择章节')
      return
    }
    setActiveTool('outline')
    setGenerating(true)
    setResult('')

    try {
      if (outlineMode === 'chapter') {
        // 为当前章节生成详细大纲
        const fullPrompt = `请分析以下章节内容，生成该章节的详细写作大纲，包括：
1. 本章核心事件
2. 主要情节点（按顺序列出）
3. 角色出场安排
4. 高潮和转折点
5. 伏笔铺设（如有）

章节内容：
${chapterContent}

章节大纲（格式清晰）：`

        await aiModelService.stream(
          'summary',
          fullPrompt,
          (chunk) => setResult(prev => prev + chunk),
          (error) => message.error(`大纲生成失败：${error}`)
        )
      } else {
        // 整本书大纲生成（需要更多上下文）
        const fullPrompt = `请根据以下已知章节内容，为这本小说生成整体大纲框架（包括：
- 主线剧情概述
- 主要角色弧光
- 关键情节点（起承转合）
- 世界观核心设定
- 伏笔和悬念布局

已有章节内容：
${chapterContent.slice(0, 3000)}

整体大纲框架：`

        await aiModelService.stream(
          'summary',
          fullPrompt,
          (chunk) => setResult(prev => prev + chunk),
          (error) => message.error(`大纲生成失败：${error}`)
        )
      }
    } catch (error) {
      message.error('大纲生成失败')
    } finally {
      setGenerating(false)
    }
  }

  // 风格迁移
  const [selectedStyle, setSelectedStyle] = useState<string>('')

  const handleStyleTransfer = async () => {
    if (!chapterContent) {
      message.warning('请先选择章节')
      return
    }
    if (!selectedStyle) {
      message.warning('请选择目标风格')
      return
    }
    setActiveTool('style')
    setGenerating(true)
    setResult('')

    try {
      const stylePrompt = STYLE_OPTIONS.find(s => s.value === selectedStyle)?.label || selectedStyle
      const fullPrompt = `请用"${stylePrompt}的风格"重写以下小说内容。保持情节不变，但采用该作家特有的叙事风格、文笔特点：

原文：
${chapterContent.slice(-1500)}

风格迁移后的内容（直接输出）：`

      await aiModelService.stream(
        'creative',
        fullPrompt,
        (chunk) => setResult(prev => prev + chunk),
        (error) => message.error(`风格迁移失败：${error}`)
      )
    } catch (error) {
      message.error('风格迁移失败')
    } finally {
      setGenerating(false)
    }
  }

  // 应用生成结果（替换/追加到编辑器）
  const handleApply = () => {
    if (!result) return
    Modal.confirm({
      title: '插入方式',
      content: '选择如何将生成内容插入编辑器：',
      okText: '追加到末尾',
      cancelText: '取消',
      onOk: () => {
        onInsertText(result)
        message.success('已追加到编辑器')
        setResult('')
      },
    })
  }

  // 替换全文
  const handleReplace = () => {
    if (!result) return
    Modal.confirm({
      title: '确认替换',
      content: '将使用生成的内容完全替换当前章节内容？',
      okText: '确认替换',
      okButtonProps: { danger: true },
      cancelText: '取消',
      onOk: () => {
        // 通过 onInsertText 返回空字符串+特殊标记让 Workbench 知道要替换
        onInsertText(`__REPLACE__${result}`)
        message.success('已替换章节内容')
        setResult('')
      },
    })
  }

  // 新增工具 Tab 配置
  const toolTabs = [
    { key: 'writing', label: '✏️ 写作' },
    { key: 'review', label: '🔍 校验' },
    { key: 'outline', label: '📋 大纲' },
  ]

  return (
    <div style={{ height: '100%', display: 'flex', flexDirection: 'column' }}>
      {/* 工具标签页 */}
      <div style={{ padding: '10px 16px 0', borderBottom: '1px solid #e8e8e8' }}>
        <Tabs
          activeKey={activeTool}
          onChange={(key) => {
            setActiveTool(key)
            setResult('')
            setExtractedFacts([])
          }}
          size="small"
          items={[
            {
              key: 'writing',
              label: '✏️ 写作',
              children: (
                <div>
                  <Space direction="vertical" style={{ width: '100%' }}>
                    <Button
                      type="primary"
                      block
                      icon={<EditOutlined />}
                      onClick={handleContinue}
                      loading={generating && activeTool === 'continue'}
                      disabled={!chapterContent}
                    >
                      智能续写
                    </Button>
                    <Button
                      block
                      icon={<ExpandOutlined />}
                      onClick={handleExpand}
                      loading={generating && activeTool === 'expand'}
                      disabled={!chapterContent}
                    >
                      定向扩写
                    </Button>
                    <Button
                      block
                      icon={<SyncOutlined />}
                      onClick={handleRewrite}
                      loading={generating && activeTool === 'rewrite'}
                      disabled={!chapterContent}
                    >
                      AI重写
                    </Button>
                    <Button
                      block
                      icon={<BgColorsOutlined />}
                      onClick={handlePolish}
                      loading={generating && activeTool === 'polish'}
                      disabled={!chapterContent}
                    >
                      AI润色
                    </Button>

                    <TextArea
                      placeholder="扩写/重写要求（可选）"
                      rows={2}
                      value={prompt}
                      onChange={(e) => setPrompt(e.target.value)}
                    />
                  </Space>

                  {activeTool === 'rewrite' && (
                    <div style={{ marginTop: 8 }}>
                      <Space>
                        <Select
                          value={rewriteMode}
                          onChange={setRewriteMode}
                          options={[
                            { value: 'chapter', label: '整章重写' },
                            { value: 'paragraph', label: '段落重写' },
                          ]}
                          style={{ width: 120 }}
                          size="small"
                        />
                      </Space>
                      <Input
                        placeholder="重写要求（可选，如：更简洁、更紧张）"
                        size="small"
                        value={rewritePrompt}
                        onChange={(e) => setRewritePrompt(e.target.value)}
                        style={{ marginTop: 6, width: '100%' }}
                      />
                    </div>
                  )}

                  {activeTool === 'polish' && (
                    <Alert
                      message="润色将改善文笔表达，精简冗余，但保持原意"
                      type="info"
                      showIcon
                      style={{ marginTop: 8, fontSize: 11 }}
                    />
                  )}
                </div>
              ),
            },
            {
              key: 'review',
              label: '🔍 校验',
              children: (
                <div>
                  <Space direction="vertical" style={{ width: '100%' }}>
                    <Button
                      block
                      icon={<CheckCircleOutlined />}
                      onClick={handleCheck}
                      loading={generating && activeTool === 'check'}
                      disabled={!chapterContent}
                    >
                      逻辑校验
                    </Button>
                    <Button
                      block
                      icon={<ThunderboltOutlined />}
                      onClick={handleExtract}
                      loading={generating && activeTool === 'extract'}
                      disabled={!chapterContent}
                    >
                      提取事实
                    </Button>
                  </Space>
                </div>
              ),
            },
            {
              key: 'outline',
              label: '📋 大纲',
              children: (
                <div>
                  <Space direction="vertical" style={{ width: '100%' }}>
                    <Button
                      block
                      icon={<ProfileOutlined />}
                      onClick={() => {
                        setOutlineMode('chapter')
                        handleGenerateOutline()
                      }}
                      loading={generating && activeTool === 'outline'}
                      disabled={!chapterContent}
                    >
                      生成本章大纲
                    </Button>
                    <Button
                      block
                      icon={<BulbOutlined />}
                      onClick={() => {
                        setOutlineMode('full')
                        handleGenerateOutline()
                      }}
                      loading={generating && activeTool === 'outline'}
                      disabled={!chapterContent}
                    >
                      生成整体大纲
                    </Button>
                    <Divider style={{ margin: '8px 0' }} />
                    <Select
                      placeholder="选择风格"
                      value={selectedStyle || undefined}
                      onChange={setSelectedStyle}
                      options={STYLE_OPTIONS}
                      style={{ width: '100%' }}
                      allowClear
                    />
                    <Button
                      block
                      icon={<BgColorsOutlined />}
                      onClick={handleStyleTransfer}
                      loading={generating && activeTool === 'style'}
                      disabled={!chapterContent || !selectedStyle}
                    >
                      风格迁移
                    </Button>
                  </Space>
                </div>
              ),
            },
          ]}
        />
      </div>

      {/* 结果显示区 */}
      <div style={{ flex: 1, overflow: 'auto', padding: 16 }}>
        {generating ? (
          <div style={{ textAlign: 'center', padding: 40 }}>
            <Spin tip="AI 生成中..." />
          </div>
        ) : result ? (
          <Card
            size="small"
            title="生成结果"
            extra={
              <Space>
                {extractedFacts.length > 0 && (
                  <Button
                    type="primary"
                    size="small"
                    icon={<SaveOutlined />}
                    onClick={handleSaveFacts}
                    loading={generating}
                  >
                    保存到台账
                  </Button>
                )}
                <Button type="link" size="small" onClick={handleApply}>
                  插入
                </Button>
                {(activeTool === 'rewrite' || activeTool === 'polish' || activeTool === 'style') && (
                  <Button type="link" size="small" onClick={handleReplace} danger>
                    替换全文
                  </Button>
                )}
              </Space>
            }
            style={{ whiteSpace: 'pre-wrap', wordBreak: 'break-all' }}
          >
            {result}
          </Card>
        ) : (
          <div style={{ color: '#999', textAlign: 'center', padding: 40 }}>
            选择上方工具开始使用 AI 辅助创作
          </div>
        )}
      </div>
    </div>
  )
}

export default AIToolsPanel

/**
 * 事实台账面板
 * 支持按类型/角色/章节筛选，伏笔状态管理，点击跳转章节
 */

import { useState, useEffect } from 'react'
import {
  List,
  Tag,
  Tabs,
  Empty,
  Spin,
  Button,
  message,
  Select,
  Input,
  Card,
  Badge,
  Space,
  Tooltip,
  Modal,
  Form,
  InputNumber,
  Switch,
} from 'antd'
import {
  ThunderboltOutlined,
  FireOutlined,
  GiftOutlined,
  TeamOutlined,
  BulbOutlined,
  ReloadOutlined,
  SearchOutlined,
  FilterOutlined,
  EyeOutlined,
  CheckOutlined,
} from '@ant-design/icons'
import factsStore, { Fact } from '../db'
import factExtractor from '../services/factExtractor'

const { TabPane } = Tabs

type FactType = 'all' | 'power' | 'item' | 'relation' | 'foreshadow'

const typeLabels: Record<FactType, { label: string; icon: React.ReactNode; color: string }> = {
  all: { label: '全部', icon: <ThunderboltOutlined />, color: 'default' },
  power: { label: '战力', icon: <FireOutlined />, color: 'red' },
  item: { label: '物品', icon: <GiftOutlined />, color: 'gold' },
  relation: { label: '关系', icon: <TeamOutlined />, color: 'blue' },
  foreshadow: { label: '伏笔', icon: <BulbOutlined />, color: 'purple' },
}

const foreshadowStatusOptions = [
  { value: '待回收', label: '待回收', color: 'orange' },
  { value: '铺设中', label: '铺设中', color: 'blue' },
  { value: '已回收', label: '已回收', color: 'green' },
]

interface FactsPanelProps {
  projectRoot?: string | null
}

const FactsPanel: React.FC<FactsPanelProps> = ({ projectRoot }) => {
  const [activeTab, setActiveTab] = useState<FactType>('all')
  const [facts, setFacts] = useState<Fact[]>([])
  const [allFacts, setAllFacts] = useState<Fact[]>([])
  const [loading, setLoading] = useState(false)
  const [searchText, setSearchText] = useState('')
  const [filterCharacter, setFilterCharacter] = useState<string>('')
  const [filterChapter, setFilterChapter] = useState<number | undefined>(undefined)
  const [showFilters, setShowFilters] = useState(false)
  const [characters, setCharacters] = useState<string[]>([])

  // 加载事实
  const loadFacts = async () => {
    setLoading(true)
    try {
      const result = await factsStore.getFacts()
      setAllFacts(result)

      // 提取所有角色名
      const charNames = Array.from(
        new Set(result.map(f => f.subject).filter(Boolean))
      ).sort() as string[]
      setCharacters(charNames)

      applyFilters(result)
    } catch (error) {
      message.error('加载事实失败')
      console.error(error)
    } finally {
      setLoading(false)
    }
  }

  // 应用筛选
  const applyFilters = (source: Fact[]) => {
    let filtered = source

    if (activeTab !== 'all') {
      filtered = filtered.filter(f => f.type === activeTab)
    }

    if (searchText) {
      const search = searchText.toLowerCase()
      filtered = filtered.filter(
        f =>
          f.subject.toLowerCase().includes(search) ||
          f.object?.toLowerCase().includes(search) ||
          f.content.toLowerCase().includes(search)
      )
    }

    if (filterCharacter) {
      filtered = filtered.filter(
        f => f.subject === filterCharacter || f.object === filterCharacter
      )
    }

    if (filterChapter) {
      filtered = filtered.filter(
        f => f.chapterStart <= filterChapter! && f.chapterEnd >= filterChapter!
      )
    }

    setFacts(filtered)
  }

  // 提取当前章节事实
  const extractCurrentChapter = async () => {
    message.info('请在编辑器中选择章节后，使用右侧「AI工具 → 提取事实」功能')
  }

  // 切换标签时重新加载
  useEffect(() => {
    loadFacts()
  }, [projectRoot])

  // 标签切换时重新筛选
  useEffect(() => {
    applyFilters(allFacts)
  }, [activeTab, searchText, filterCharacter, filterChapter])

  // 跳转到相关章节
  const handleJumpToChapter = (fact: Fact) => {
    if (fact.type === 'foreshadow') {
      message.info(`跳转到第 ${fact.chapterStart} 章`)
    }
  }

  // 更新伏笔状态
  const handleUpdateForeshadowStatus = async (
    fact: Fact,
    newStatus: string
  ) => {
    if (!projectRoot) return
    try {
      const plotFactsFile = `${projectRoot}/facts/plot_facts.yaml`
      const result = await window.electronAPI.yaml.read(plotFactsFile)
      if (result.success && result.data) {
        const plotData = result.data as Record<string, unknown>
        const foreshadowList = (plotData['伏笔清单'] as Array<Record<string, unknown>>) || []
        const updated = foreshadowList.map(fb => {
          if (fb['description'] === fact.content) {
            return { ...fb, status: newStatus }
          }
          return fb
        })
        plotData['伏笔清单'] = updated
        await window.electronAPI.yaml.write(plotFactsFile, plotData)
        message.success(`伏笔状态已更新为「${newStatus}」`)
        loadFacts()
      }
    } catch (error) {
      message.error('更新失败')
    }
  }

  // 格式化事实项
  const renderFactItem = (item: Fact) => {
    const typeInfo = typeLabels[item.type as FactType]
    const isForeshadow = item.type === 'foreshadow'

    return (
      <List.Item
        key={item.id}
        style={{
          opacity: isForeshadow ? 1 : 1,
          cursor: 'pointer',
        }}
        onClick={() => handleJumpToChapter(item)}
      >
        <List.Item.Meta
          title={
            <div style={{ display: 'flex', alignItems: 'center', gap: 8, flexWrap: 'wrap' }}>
              <Tag color={typeInfo.color}>
                {typeInfo.icon} {typeInfo.label}
              </Tag>
              <strong>{item.subject}</strong>
              {item.object && (
                <>
                  <span style={{ color: '#999' }}>→</span>
                  <strong>{item.object}</strong>
                </>
              )}
              {isForeshadow && (
                <Tag
                  color={
                    item.content.includes('已回收')
                      ? 'green'
                      : item.content.includes('铺设中')
                        ? 'blue'
                        : 'orange'
                  }
                  style={{ marginLeft: 4 }}
                >
                  {item.content.includes('已回收') ? '已回收' : item.content.includes('铺设中') ? '铺设中' : '待回收'}
                </Tag>
              )}
            </div>
          }
          description={
            <div>
              <p style={{ margin: '4px 0' }}>{item.content}</p>
              <div
                style={{
                  fontSize: 12,
                  color: '#999',
                  marginTop: 4,
                  display: 'flex',
                  justifyContent: 'space-between',
                  alignItems: 'center',
                }}
              >
                <span>
                  第 {item.chapterStart} 章
                  {item.chapterEnd !== item.chapterStart && ` - 第 ${item.chapterEnd} 章`}
                </span>
                {isForeshadow && (
                  <Space size="small">
                    {['待回收', '铺设中', '已回收'].map(status => (
                      <Button
                        key={status}
                        size="small"
                        type="text"
                        style={{ fontSize: 11, padding: '0 4px', height: 20 }}
                        onClick={(e) => {
                          e.stopPropagation()
                          handleUpdateForeshadowStatus(item, status)
                        }}
                      >
                        {status}
                      </Button>
                    ))}
                  </Space>
                )}
              </div>
            </div>
          }
        />
      </List.Item>
    )
  }

  // 统计摘要
  const getSummary = () => {
    const stats = {
      total: allFacts.length,
      power: allFacts.filter(f => f.type === 'power').length,
      item: allFacts.filter(f => f.type === 'item').length,
      relation: allFacts.filter(f => f.type === 'relation').length,
      foreshadow: allFacts.filter(f => f.type === 'foreshadow').length,
      foreshadowPending: allFacts.filter(
        f =>
          f.type === 'foreshadow' &&
          !f.content.includes('已回收') &&
          !f.content.includes('铺设中')
      ).length,
    }
    return stats
  }

  const stats = getSummary()

  return (
    <div style={{ height: '100%', display: 'flex', flexDirection: 'column' }}>
      {/* 头部 */}
      <div style={{ padding: '10px 16px', borderBottom: '1px solid #e8e8e8' }}>
        {/* 统计栏 */}
        <div
          style={{
            display: 'flex',
            gap: 8,
            marginBottom: 10,
            flexWrap: 'wrap',
            fontSize: 12,
          }}
        >
          <Badge count={stats.total} showZero color="#1890ff" style={{ fontSize: 11 }}>
            <span style={{ padding: '2px 8px', background: '#f0f0f0', borderRadius: 4 }}>全部</span>
          </Badge>
          <Badge count={stats.power} showZero color="#ff4d4f" style={{ fontSize: 11 }}>
            <span style={{ padding: '2px 8px', background: '#f0f0f0', borderRadius: 4 }}>战力</span>
          </Badge>
          <Badge count={stats.relation} showZero color="#1677ff" style={{ fontSize: 11 }}>
            <span style={{ padding: '2px 8px', background: '#f0f0f0', borderRadius: 4 }}>关系</span>
          </Badge>
          <Badge count={stats.foreshadow} showZero color="#722ed1" style={{ fontSize: 11 }}>
            <span style={{ padding: '2px 8px', background: '#f0f0f0', borderRadius: 4 }}>
              伏笔
              {stats.foreshadowPending > 0 && ` (${stats.foreshadowPending}待收)`}
            </span>
          </Badge>
        </div>

        {/* 搜索和筛选 */}
        <div style={{ display: 'flex', gap: 8, alignItems: 'center', marginBottom: 10 }}>
          <Input
            placeholder="搜索事实..."
            prefix={<SearchOutlined />}
            value={searchText}
            onChange={(e) => setSearchText(e.target.value)}
            allowClear
            size="small"
            style={{ flex: 1 }}
          />
          <Button
            size="small"
            icon={<FilterOutlined />}
            onClick={() => setShowFilters(!showFilters)}
            type={showFilters ? 'primary' : 'default'}
          >
            筛选
          </Button>
          <Button
            size="small"
            icon={<ReloadOutlined />}
            onClick={loadFacts}
          />
        </div>

        {/* 高级筛选 */}
        {showFilters && (
          <div style={{ marginBottom: 10, padding: 8, background: '#f5f5f5', borderRadius: 6 }}>
            <Space direction="vertical" style={{ width: '100%' }}>
              <Select
                placeholder="按角色筛选"
                value={filterCharacter || undefined}
                onChange={(val) => setFilterCharacter(val || '')}
                options={characters.map(c => ({ value: c, label: c }))}
                style={{ width: '100%' }}
                size="small"
                allowClear
                showSearch
              />
              <InputNumber
                placeholder="按章节筛选"
                value={filterChapter}
                onChange={(val) => setFilterChapter(val ?? undefined)}
                min={1}
                style={{ width: '100%' }}
                size="small"
              />
              <Button
                size="small"
                onClick={() => {
                  setFilterCharacter('')
                  setFilterChapter(undefined)
                }}
              >
                清除筛选
              </Button>
            </Space>
          </div>
        )}

        <Tabs
          activeKey={activeTab}
          onChange={(key) => setActiveTab(key as FactType)}
          size="small"
        >
          {Object.entries(typeLabels).map(([key, info]) => (
            <TabPane
              key={key}
              tab={<span>{info.icon} {info.label}</span>}
            />
          ))}
        </Tabs>
      </div>

      {/* 列表 */}
      <div style={{ flex: 1, overflow: 'auto', padding: '0 16px' }}>
        {loading ? (
          <div style={{ padding: 40, textAlign: 'center' }}>
            <Spin tip="加载中..." />
          </div>
        ) : facts.length === 0 ? (
          <div style={{ padding: 40, textAlign: 'center' }}>
            <Empty
              description="暂无事实记录"
              image={Empty.PRESENTED_IMAGE_SIMPLE}
            />
          </div>
        ) : (
          <List
            dataSource={facts}
            renderItem={renderFactItem}
            size="small"
            style={{ padding: '10px 0' }}
          />
        )}
      </div>
    </div>
  )
}

export default FactsPanel

import { useEffect, useRef, useState } from 'react'
import * as monaco from 'monaco-editor'
import { Spin } from 'antd'
import { loader } from '@monaco-editor/react'

// 配置 Monaco Editor 加载路径
loader.config({
  paths: {
    vs: 'https://cdn.jsdelivr.net/npm/monaco-editor@0.45.0/min/vs'
  }
})

interface EditorProps {
  value: string
  onChange: (value: string | undefined) => void
  filePath?: string
}

const Editor = ({ value, onChange, filePath }: EditorProps) => {
  const editorRef = useRef<HTMLDivElement>(null)
  const monacoEditorRef = useRef<monaco.editor.IStandaloneCodeEditor | null>(null)
  const [loading, setLoading] = useState(true)

  // 初始化编辑器
  useEffect(() => {
    if (!editorRef.current) return

    let isMounted = true

    const initEditor = async () => {
      try {
        // 加载 Monaco Editor
        await loader.init()

        if (!isMounted || !editorRef.current) return

        // 创建编辑器实例
        const editor = monaco.editor.create(editorRef.current, {
          value,
          language: 'markdown',
          theme: 'vs-light',
          fontSize: 16,
          lineHeight: 1.8,
          lineNumbers: 'on',
          wordWrap: 'on',
          wrappingIndent: 'indent',
          automaticLayout: true,
          minimap: { enabled: false },
          scrollBeyondLastLine: false,
          tabSize: 2,
          insertSpaces: true,
          renderWhitespace: 'none',
          renderLineHighlight: 'line',
          scrollbar: {
            verticalScrollbarSize: 10,
            horizontalScrollbarSize: 10,
          },
        })

        // 监听内容变化
        editor.onDidChangeModelContent(() => {
          const newValue = editor.getValue()
          onChange(newValue)
        })

        // 保存快捷键
        editor.addCommand(monaco.KeyMod.CtrlCmd | monaco.KeyCode.KeyS, () => {
          // 保存由 Workbench 处理
          const saveEvent = new KeyboardEvent('keydown', {
            key: 's',
            ctrlKey: true,
            bubbles: true
          })
          window.dispatchEvent(saveEvent)
        })

        monacoEditorRef.current = editor
        setLoading(false)
      } catch (error) {
        console.error('初始化编辑器失败:', error)
        setLoading(false)
      }
    }

    initEditor()

    return () => {
      isMounted = false
      if (monacoEditorRef.current) {
        monacoEditorRef.current.dispose()
        monacoEditorRef.current = null
      }
    }
  }, [])

  // 当外部 value 变化时更新编辑器内容
  useEffect(() => {
    if (!monacoEditorRef.current) return

    const currentValue = monacoEditorRef.current.getValue()
    if (currentValue !== value) {
      monacoEditorRef.current.setValue(value)
    }
  }, [value])

  // 根据文件类型切换语言模式
  useEffect(() => {
    if (!monacoEditorRef.current || !filePath) return

    const model = monacoEditorRef.current.getModel()
    if (!model) return

    if (filePath.endsWith('.md') || filePath.endsWith('.markdown')) {
      monaco.editor.setModelLanguage(model, 'markdown')
    } else if (filePath.endsWith('.yaml') || filePath.endsWith('.yml')) {
      monaco.editor.setModelLanguage(model, 'yaml')
    } else if (filePath.endsWith('.json')) {
      monaco.editor.setModelLanguage(model, 'json')
    }
  }, [filePath])

  if (loading) {
    return (
      <div style={{ height: '100%', display: 'flex', alignItems: 'center', justifyContent: 'center' }}>
        <Spin tip="加载编辑器中..." />
      </div>
    )
  }

  return (
    <div ref={editorRef} style={{ width: '100%', height: '100%' }} />
  )
}

export default Editor

/**
 * 项目管理器
 * 创建新项目、打开项目、项目列表
 */

import { useState, useEffect } from 'react'
import {
  Modal,
  Form,
  Input,
  Select,
  Button,
  Space,
  Divider,
  message,
  List,
  Card,
  Tag,
  Empty,
} from 'antd'
import {
  PlusOutlined,
  FolderOpenOutlined,
  FileOutlined,
  DeleteOutlined,
  ProjectOutlined,
} from '@ant-design/icons'
import factsStore from '../db'

interface ProjectInfo {
  name: string
  path: string
  genre: string
  status: string
  lastModified: string
}

interface ProjectManagerProps {
  visible: boolean
  mode?: 'create' | 'list'
  onClose: () => void
  onProjectOpened: (projectPath: string) => void
}

// 默认项目结构
const DEFAULT_PROJECT_STRUCTURE = {
  plots: {
    '第一卷_觉醒': {
      '_plan.yaml': `# 第一卷：觉醒

## 卷概要
重生少年林枫，在修仙世界重新开始。

## 主要线索
- 林枫重生，改变命运
- 青云宗入门测试
- 发现血魔宗阴谋

## 章节规划
- 第1-10章：重生与入门
- 第11-30章：成长与冲突
- 第31-50章：揭露阴谋
`,
    },
  },
  characters: {},
  settings: {},
  facts: {
    characters_facts: {},
    plot_facts: {
      伏笔清单: [],
    },
    settings_facts: {},
  },
  'relationships.yaml': `# 人物关系索引
relationships: []
`,
  'project.yaml': '',
}

const GENRE_OPTIONS = [
  { value: 'xianxia', label: '玄幻修仙' },
  { value: 'urban', label: '都市异能' },
  { value: 'game', label: '游戏世界' },
  { value: 'scifi', label: '科幻末世' },
  { value: 'fantasy', label: '奇幻冒险' },
  { value: 'romance', label: '言情' },
  { value: 'xuanhuan', label: '玄幻爽文' },
]

const ProjectManager: React.FC<ProjectManagerProps> = ({
  visible,
  mode: initialMode,
  onClose,
  onProjectOpened,
}) => {
  const [mode, setMode] = useState<'create' | 'list'>(initialMode || 'create')
  const [form] = Form.useForm()
  const [creating, setCreating] = useState(false)
  const [recentProjects, setRecentProjects] = useState<ProjectInfo[]>([])

  // 加载最近项目
  const loadRecentProjects = async () => {
    try {
      const result = await window.electronAPI.ai.getSetting('recentProjects', [])
      if (result.success && result.value) {
        setRecentProjects(result.value as ProjectInfo[])
      }
    } catch {
      // ignore
    }
  }

  useEffect(() => {
    if (visible) {
      loadRecentProjects()
      setMode(initialMode || 'create')
    }
  }, [visible, initialMode])

  // 创建新项目
  const handleCreateProject = async () => {
    try {
      const values = await form.validateFields()
      setCreating(true)

      // 弹出目录选择对话框
      const parentDir = await window.electronAPI.openDirectory()
      if (!parentDir) {
        setCreating(false)
        return
      }

      const projectName = values.name.replace(/[/\\?%*:|"<>]/g, '_')
      const projectPath = `${parentDir}/${projectName}`

      // 创建项目目录结构
      await createProjectStructure(projectPath, values)

      // 添加到最近项目
      const projectInfo: ProjectInfo = {
        name: values.name,
        path: projectPath,
        genre: values.genre,
        status: 'planning',
        lastModified: new Date().toISOString().split('T')[0],
      }

      const updatedRecent = [
        projectInfo,
        ...recentProjects.filter(p => p.path !== projectPath),
      ].slice(0, 10) // 最多保留10个最近项目

      await window.electronAPI.ai.saveSetting('recentProjects', updatedRecent)

      message.success(`项目「${values.name}」创建成功！`)
      onProjectOpened(projectPath)
      onClose()
    } catch (error) {
      console.error('创建项目失败:', error)
      message.error('创建项目失败')
    } finally {
      setCreating(false)
    }
  }

  // 创建项目目录结构
  const createProjectStructure = async (
    projectPath: string,
    projectInfo: Record<string, unknown>
  ) => {
    // project.yaml
    const projectYaml = {
      title: projectInfo.name,
      author: projectInfo.author || '你的名字',
      genre: projectInfo.genre || 'xianxia',
      target_words: projectInfo.targetWords || 200000,
      status: 'planning',
      created: new Date().toISOString().split('T')[0],
      last_modified: new Date().toISOString().split('T')[0],
    }

    await window.electronAPI.yaml.write(
      `${projectPath}/project.yaml`,
      projectYaml
    )

    // plots 目录和示例章节
    const plotsPath = `${projectPath}/plots`
    const volumePath = `${plotsPath}/第一卷_觉醒`
    await window.electronAPI.mkdir(volumePath)

    // 示例章节
    const sampleChapter = `# 第一章 重生

睁开眼，熟悉的场景映入眼帘。

这是……青云宗？

林枫猛地坐起身，环顾四周。一切都那么熟悉，却又带着一种说不出的陌生感。

他记得自己明明已经死了，死在血魔宗那场围杀之中。可是现在……

低头看着自己的双手，年轻而有力。这双手，应该已经在五百年前那场大战中化为灰烬了。

\"我……重生了？\"

林枫喃喃自语，眼中闪过一丝复杂的光芒。前世的记忆如潮水般涌来——血魔的背叛、师门的覆灭、以及那场改变一切的决战。

既然上天给了他第二次机会……

这一世，他绝不会再让悲剧重演。

血魔宗，你们等着！
`

    await window.electronAPI.writeFile(
      `${volumePath}/第一章_重生.md`,
      sampleChapter
    )

    await window.electronAPI.writeFile(
      `${volumePath}/_plan.yaml`,
      DEFAULT_PROJECT_STRUCTURE.plots['第一卷_觉醒']['_plan.yaml']
    )

    // characters 目录
    await window.electronAPI.mkdir(`${projectPath}/characters`)

    // settings 目录
    await window.electronAPI.mkdir(`${projectPath}/settings`)

    // facts 目录
    await window.electronAPI.mkdir(`${projectPath}/facts`)
    await window.electronAPI.yaml.write(
      `${projectPath}/facts/plot_facts.yaml`,
      { 伏笔清单: [] }
    )

    // relationships.yaml
    await window.electronAPI.writeFile(
      `${projectPath}/relationships.yaml`,
      DEFAULT_PROJECT_STRUCTURE['relationships.yaml']
    )
  }

  // 打开最近项目
  const handleOpenRecentProject = (project: ProjectInfo) => {
    onProjectOpened(project.path)
    onClose()
  }

  // 删除最近项目记录
  const handleRemoveRecentProject = async (project: ProjectInfo) => {
    const updated = recentProjects.filter(p => p.path !== project.path)
    setRecentProjects(updated)
    await window.electronAPI.ai.saveSetting('recentProjects', updated)
    message.success('已从列表中移除')
  }

  return (
    <Modal
      title={mode === 'create' ? '📖 创建新项目' : '📂 最近项目'}
      open={visible}
      onCancel={onClose}
      width={600}
      footer={null}
      bodyStyle={{ maxHeight: '70vh', overflow: 'auto' }}
    >
      <div style={{ display: 'flex', gap: 8, marginBottom: 16 }}>
        <Button
          type={mode === 'create' ? 'primary' : 'default'}
          onClick={() => setMode('create')}
        >
          创建新项目
        </Button>
        <Button
          type={mode === 'list' ? 'primary' : 'default'}
          onClick={() => setMode('list')}
        >
          最近项目
        </Button>
      </div>

      {mode === 'create' ? (
        <Form
          form={form}
          layout="vertical"
          initialValues={{
            genre: 'xianxia',
            targetWords: 200000,
            author: '',
          }}
        >
          <Form.Item
            name="name"
            label="项目名称"
            rules={[{ required: true, message: '请输入项目名称' }]}
          >
            <Input placeholder="如：剑仙归来、都市修仙传" />
          </Form.Item>

          <Form.Item name="author" label="作者">
            <Input placeholder="你的笔名（可选）" />
          </Form.Item>

          <Form.Item
            name="genre"
            label="题材类型"
            rules={[{ required: true, message: '请选择题材' }]}
          >
            <Select options={GENRE_OPTIONS} />
          </Form.Item>

          <Form.Item
            name="targetWords"
            label="目标字数"
          >
            <Select
              options={[
                { value: 50000, label: '5万字（短篇）' },
                { value: 100000, label: '10万字（中篇）' },
                { value: 200000, label: '20万字（长篇）' },
                { value: 500000, label: '50万字（超长篇）' },
                { value: 1000000, label: '100万字（百万巨著）' },
              ]}
            />
          </Form.Item>

          <Divider />

          <div style={{ color: '#999', fontSize: 12, marginBottom: 12 }}>
            点击「创建」后将弹出目录选择对话框，请选择项目的保存位置。
            项目将自动创建完整的目录结构。
          </div>

          <Button
            type="primary"
            icon={<PlusOutlined />}
            block
            loading={creating}
            onClick={handleCreateProject}
          >
            选择目录并创建项目
          </Button>
        </Form>
      ) : (
        <div>
          {recentProjects.length === 0 ? (
            <Empty
              description="暂无最近项目"
              image={Empty.PRESENTED_IMAGE_SIMPLE}
            >
              <Button type="primary" onClick={() => setMode('create')}>
                创建新项目
              </Button>
            </Empty>
          ) : (
            <List
              grid={{ gutter: 12, xs: 1, sm: 2 }}
              dataSource={recentProjects}
              renderItem={(project) => (
                <List.Item>
                  <Card
                    size="small"
                    hoverable
                    actions={[
                      <Button
                        key="open"
                        type="link"
                        icon={<FolderOpenOutlined />}
                        onClick={() => handleOpenRecentProject(project)}
                      >
                        打开
                      </Button>,
                      <Button
                        key="remove"
                        type="link"
                        danger
                        icon={<DeleteOutlined />}
                        onClick={() => handleRemoveRecentProject(project)}
                      >
                        移除
                      </Button>,
                    ]}
                  >
                    <Card.Meta
                      avatar={<ProjectOutlined style={{ fontSize: 24, color: '#1890ff' }} />}
                      title={project.name}
                      description={
                        <div style={{ fontSize: 12, color: '#999' }}>
                          <div style={{ marginBottom: 4 }}>
                            <Tag>{GENRE_OPTIONS.find(g => g.value === project.genre)?.label || project.genre}</Tag>
                            <Tag color={project.status === 'writing' ? 'green' : 'orange'}>
                              {project.status === 'writing' ? '创作中' : '规划中'}
                            </Tag>
                          </div>
                          <div style={{ wordBreak: 'break-all', fontSize: 11 }}>
                            {project.path}
                          </div>
                        </div>
                      }
                    />
                  </Card>
                </List.Item>
              )}
            />
          )}
        </div>
      )}
    </Modal>
  )
}

