  }
}

/**
 * 设置项目根路径
 */
function setProjectRoot(rootPath: string): void {
  projectRootPath = path.resolve(rootPath)
}

/**
 * 设置 IPC 处理器
 * 所有主进程功能通过 IPC 暴露给渲染进程
 */
function setupIpcHandlers(): void {
  // ========== 对话框 ==========
  ipcMain.handle('dialog:openDirectory', async () => {
    const result = await dialog.showOpenDialog({
      properties: ['openDirectory'],
    })

    if (!result.canceled && result.filePaths.length > 0) {
      const selectedPath = result.filePaths[0]
      setProjectRoot(selectedPath)
      return selectedPath
    }
    return undefined
  })

  // ========== 文件系统 - 读取操作 ==========
  ipcMain.handle('fs:readFile', async (_event, filePath: string) => {
    try {
      const validation = validatePath(filePath)
      if (!validation.valid) {
        return { success: false, error: validation.error }
      }

      const content = await fs.promises.readFile(validation.resolvedPath!, 'utf-8')
      return { success: true, content }
    } catch (error: any) {
      return { success: false, error: error.message }
    }
  })

  ipcMain.handle('fs:exists', async (_event, filePath: string) => {
    try {
      const validation = validatePath(filePath)
      if (!validation.valid) {
        return false
      }

      await fs.promises.access(validation.resolvedPath!)
      return true
    } catch {
      return false
    }
  })

  ipcMain.handle('fs:readdir', async (_event, dirPath: string) => {
    try {
      const validation = validatePath(dirPath)
      if (!validation.valid) {
        return { success: false, error: validation.error }
      }

      const entries = await fs.promises.readdir(validation.resolvedPath!, { withFileTypes: true })
      const result = entries.map(entry => ({
        name: entry.name,
        isDirectory: entry.isDirectory(),
        isFile: entry.isFile(),
      }))
      return result
    } catch (error: any) {
      return { success: false, error: error.message }
    }
  })

  // ========== 文件系统 - 写入操作 ==========
  ipcMain.handle('fs:writeFile', async (_event, filePath: string, content: string) => {
    try {
      const validation = validatePath(filePath)
      if (!validation.valid) {
        return { success: false, error: validation.error }
      }

      // 确保父目录存在
      const dir = path.dirname(validation.resolvedPath!)
      await fs.promises.mkdir(dir, { recursive: true })

      await fs.promises.writeFile(validation.resolvedPath!, content, 'utf-8')
      return { success: true }
    } catch (error: any) {
      return { success: false, error: error.message }
    }
  })

  ipcMain.handle('fs:mkdir', async (_event, dirPath: string) => {
    try {
      const validation = validatePath(dirPath)
      if (!validation.valid) {
        return { success: false, error: validation.error }
      }

      await fs.promises.mkdir(validation.resolvedPath!, { recursive: true })
      return { success: true }
    } catch (error: any) {
      return { success: false, error: error.message }
    }
  })

  // ========== 文件系统 - 删除操作 ==========
  ipcMain.handle('fs:unlink', async (_event, filePath: string) => {
    try {
      const validation = validatePath(filePath)
      if (!validation.valid) {
        return { success: false, error: validation.error }
      }

      await fs.promises.unlink(validation.resolvedPath!)
      return { success: true }
    } catch (error: any) {
      return { success: false, error: error.message }
    }
  })

  ipcMain.handle('fs:rmdir', async (_event, dirPath: string, options?: { recursive?: boolean }) => {
    try {
      const validation = validatePath(dirPath)
      if (!validation.valid) {
        return { success: false, error: validation.error }
      }

      await fs.promises.rm(validation.resolvedPath!, { recursive: options?.recursive, force: true })
      return { success: true }
    } catch (error: any) {
      return { success: false, error: error.message }
    }
  })

  ipcMain.handle('fs:remove', async (_event, targetPath: string) => {
    try {
      const validation = validatePath(targetPath)
      if (!validation.valid) {
        return { success: false, error: validation.error }
      }

      await fs.promises.rm(validation.resolvedPath!, { recursive: true })
      return { success: true }
    } catch (error: any) {
      return { success: false, error: error.message }
    }
  })

  ipcMain.handle('fs:rename', async (_event, oldPath: string, newPath: string) => {
    try {
      const oldValidation = validatePath(oldPath)
      const newValidation = validatePath(newPath)

      if (!oldValidation.valid) {
        return { success: false, error: oldValidation.error }
      }
      if (!newValidation.valid) {
        return { success: false, error: newValidation.error }
      }

      await fs.promises.rename(oldValidation.resolvedPath!, newValidation.resolvedPath!)
      return { success: true }
    } catch (error: any) {
      return { success: false, error: error.message }
    }
  })

  // ========== 系统 ==========
  ipcMain.handle('shell:openPath', async (_event, path: string) => {
    return shell.openPath(path)
  })

  // ========== 项目 ==========
  ipcMain.handle('project:getRoot', () => {
    return projectRootPath
  })

  // ========== 文件系统监听 ==========
  ipcMain.handle('fs:watch', async (_event, dirPath?: string) => {
    try {
      // 停止之前的监视
      if (fsWatcher) {
        await fsWatcher.close()
        fsWatcher = null
      }

      const watchPath = dirPath 
        ? validatePath(dirPath).resolvedPath 
        : projectRootPath

      if (!watchPath) {
        return { success: false, error: '没有可监视的路径' }
      }

      fsWatcher = fs.watch(watchPath, { recursive: true }, (eventType, filename) => {
        if (filename && mainWindow) {
          mainWindow.webContents.send('fs:change', {
            type: eventType,
            fileName: filename,
            path: path.join(watchPath, filename),
          })
        }
      })

      return { success: true, path: watchPath }
    } catch (error: any) {
      return { success: false, error: error.message }
    }
  })

  ipcMain.handle('fs:unwatch', async () => {
    try {
      if (fsWatcher) {
        await fsWatcher.close()
        fsWatcher = null
      }
      return { success: true }
    } catch (error: any) {
      return { success: false, error: error.message }
    }
  })

  // ========== 安全存储 ==========
  ipcMain.handle('safeStorage:encrypt', async (_event, plainText: string) => {
    try {
      if (!safeStorage.isEncryptionAvailable()) {
        return { success: false, error: '加密不可用' }
      }
      const encrypted = safeStorage.encryptString(plainText)
      return { success: true, data: encrypted }
    } catch (error: any) {
      return { success: false, error: error.message }
    }
  })

  ipcMain.handle('safeStorage:decrypt', async (_event, encrypted: Buffer) => {
    try {
      if (!safeStorage.isEncryptionAvailable()) {
        return { success: false, error: '加密不可用' }
      }
      const decrypted = safeStorage.decryptString(encrypted)
      return { success: true, data: decrypted }
    } catch (error: any) {
      return { success: false, error: error.message }
    }
  })

  ipcMain.handle('safeStorage:isAvailable', () => {
    return { success: true, available: safeStorage.isEncryptionAvailable() }
  })

  // ========== AI 服务 ==========
  // 导入 AI 服务
  const { setupAiHandlers } = require('./aiService')
  setupAiHandlers(ipcMain)

  // ========== 备份服务 ==========
  // 导入备份服务
  const { setupBackupHandlers } = require('./backupService')
  setupBackupHandlers(ipcMain)

  // ========== YAML 服务 ==========
  setupYamlHandlers(ipcMain)
}

/**
 * 启动应用
 */
async function startApp(): Promise<void> {
  // 设置 IPC 处理器
  setupIpcHandlers()

  // 创建窗口
  createWindow()

  // 加载应用
  if (process.env.NODE_ENV === 'development') {
    await mainWindow?.loadURL('http://localhost:5173')
    mainWindow?.webContents.openDevTools()
  } else {
    await mainWindow?.loadFile(path.join(__dirname, '../renderer/index.html'))
  }
}

// 应用就绪
app.whenReady().then(startApp)

// 所有窗口关闭时退出
app.on('window-all-closed', () => {
  if (process.platform !== 'darwin') {
    app.quit()
  }
})

app.on('activate', () => {
  if (BrowserWindow.getAllWindows().length === 0) {
    createWindow()
  }
})

// 导出供测试和主进程入口使用
export { 
  createWindow, 
  closeWindow, 
  setupIpcHandlers, 
  setProjectRoot,
  startApp,
  projectRootPath 
}

/**
 * 世界设定页面
 * 显示世界观设定列表，支持新建、编辑、删除设定
 */

import { useState, useEffect } from 'react'
import {
  Card,
  Row,
  Col,
  Button,
  Input,
  Empty,
  Spin,
  Tag,
  message,
  Modal,
  List,
  Space,
  Dropdown,
} from 'antd'
import {
  PlusOutlined,
  SearchOutlined,
  EditOutlined,
  DeleteOutlined,
  SettingOutlined,
  CheckCircleOutlined,
} from '@ant-design/icons'
import type { MenuProps } from 'antd'
import SettingDetail from './SettingDetail'
import aiModelService from '../services/aiModels'

interface WorldSetting {
  id: string
  name: string
  filePath: string
  summary?: string
  category?: string
}

interface SettingsPageProps {
  projectRoot: string | null
}

const SettingsPage: React.FC<SettingsPageProps> = ({ projectRoot }) => {
  const [settings, setSettings] = useState<WorldSetting[]>([])
  const [loading, setLoading] = useState(false)
  const [searchText, setSearchText] = useState('')
  const [selectedSetting, setSelectedSetting] = useState<WorldSetting | null>(null)
  const [detailVisible, setDetailVisible] = useState(false)
  const [checkingConsistency, setCheckingConsistency] = useState(false)

  // 加载设定列表
  const loadSettings = async () => {
    if (!projectRoot) return
    setLoading(true)
    try {
      const settingsDir = `${projectRoot}/settings`
      const dirExists = await window.electronAPI.exists(settingsDir)
      if (!dirExists) {
        await window.electronAPI.mkdir(settingsDir)
        setSettings([])
        return
      }

      const entries = await window.electronAPI.readdir(settingsDir)
      const settingFiles = entries.filter(
        (e: { name: string; isFile: boolean }) => e.isFile && e.name.endsWith('.yaml')
      )

      const loadedSettings: WorldSetting[] = []
      for (const file of settingFiles) {
        const filePath = `${settingsDir}/${file.name}`
        const result = await window.electronAPI.yaml.read(filePath)
        if (result.success && result.data) {
          const data = result.data as Record<string, unknown>
          // 提取第一行作为摘要（去掉 # 注释）
          const rawContent = typeof data._raw === 'string'
            ? data._raw
            : ''
          loadedSettings.push({
            id: file.name.replace('.yaml', ''),
            name: String(data.name || file.name.replace('.yaml', '')),
            filePath,
            summary: typeof data.summary === 'string' ? data.summary : rawContent.slice(0, 100),
            category: data.category as string | undefined,
          })
        }
      }

      setSettings(loadedSettings)
    } catch (error) {
      console.error('加载设定失败:', error)
      message.error('加载设定列表失败')
    } finally {
      setLoading(false)
    }
  }

  // 新建设定
  const handleNewSetting = () => {
    setSelectedSetting(null)
    setDetailVisible(true)
  }

  // 编辑设定
  const handleEditSetting = (setting: WorldSetting) => {
    setSelectedSetting(setting)
    setDetailVisible(true)
  }

  // 删除设定
  const handleDeleteSetting = async (setting: WorldSetting) => {
    Modal.confirm({
      title: `确认删除设定「${setting.name}」？`,
      content: '删除后可通过备份恢复。',
      okText: '确认删除',
      okType: 'danger',
      cancelText: '取消',
      onOk: async () => {
        try {
          const result = await window.electronAPI.deleteFile(setting.filePath)
          if (result.success) {
            message.success(`已删除设定「${setting.name}」`)
            loadSettings()
          } else {
            message.error(`删除失败: ${result.error}`)
          }
        } catch (error) {
          message.error('删除失败')
        }
      },
    })
  }

  // AI 一致性检查
  const handleConsistencyCheck = async () => {
    if (!projectRoot) return
    setCheckingConsistency(true)
    try {
      // 收集所有设定文件内容
      const settingsDir = `${projectRoot}/settings`
      const entries = await window.electronAPI.readdir(settingsDir)
      const settingFiles = entries.filter(
        (e: { name: string; isFile: boolean }) => e.isFile && e.name.endsWith('.yaml')
      )

      let allSettingsContent = ''
      for (const file of settingFiles) {
        const result = await window.electronAPI.yaml.read(`${settingsDir}/${file.name}`)
        if (result.success && result.data) {
          allSettingsContent += `\n### ${file.name.replace('.yaml', '')} ###\n`
          allSettingsContent += JSON.stringify(result.data, null, 2)
        }
      }

      if (!allSettingsContent.trim()) {
        message.warning('暂无设定可检查')
        return
      }

      const checkPrompt = `请检查以下世界设定内容，找出其中的矛盾点和不一致之处：

${allSettingsContent}

检查维度：
1. 战力体系是否矛盾（等级划分是否自洽）
2. 地理/空间设定是否冲突
3. 势力/门派设定是否矛盾
4. 时间线是否自洽
5. 能力设定是否有冲突

请列出发现的所有矛盾点，并给出修改建议。如果一切自洽，也请明确说明。`

      const result = await aiModelService.call(
        'logic',
        checkPrompt,
        {
          systemPrompt: '你是一个严格的世界观设定审核专家。请仔细检查设定的逻辑一致性。',
        }
      )

      if (result.success && result.content) {
        Modal.info({
          title: '🏛️ 世界观一致性检查结果',
          content: (
            <pre style={{
              maxHeight: 400,
              overflow: 'auto',
              whiteSpace: 'pre-wrap',
              fontSize: 13,
              fontFamily: 'monospace',
            }}>
              {result.content}
            </pre>
          ),
          width: 700,
          okText: '关闭',
        })
      } else {
        message.error(result.error || '检查失败')
      }
    } catch (error) {
      message.error('一致性检查失败')
    } finally {
      setCheckingConsistency(false)
    }
  }

  // 保存后刷新
  const handleSettingSaved = () => {
    setDetailVisible(false)
    loadSettings()
  }

  useEffect(() => {
    loadSettings()
  }, [projectRoot])

  // 过滤
  const filteredSettings = settings.filter(s =>
    s.name.toLowerCase().includes(searchText.toLowerCase())
  )

  if (!projectRoot) {
    return (
      <div style={{ padding: 40, textAlign: 'center' }}>
        <Empty description="请先打开一个小说项目" />
      </div>
    )
  }

  return (
    <div style={{ height: '100%', display: 'flex', flexDirection: 'column' }}>
      {/* 工具栏 */}
      <div style={{ padding: '12px 16px', borderBottom: '1px solid #e8e8e8' }}>
        <div
          style={{
            display: 'flex',
            justifyContent: 'space-between',
            alignItems: 'center',
            marginBottom: 10,
          }}
        >
          <h3 style={{ margin: 0 }}>世界观设定</h3>
          <Space>
            <Button
              icon={<CheckCircleOutlined />}
              onClick={handleConsistencyCheck}
              loading={checkingConsistency}
            >
              AI一致性检查
            </Button>
            <Button
              type="primary"
              icon={<PlusOutlined />}
              onClick={handleNewSetting}
            >
              新建设定
            </Button>
          </Space>
        </div>
        <Input
          placeholder="搜索设定..."
          prefix={<SearchOutlined />}
          value={searchText}
          onChange={(e) => setSearchText(e.target.value)}
          allowClear
        />
      </div>

      {/* 设定列表 */}
      <div style={{ flex: 1, overflow: 'auto', padding: 16 }}>
        {loading ? (
          <div style={{ textAlign: 'center', padding: 40 }}>
            <Spin tip="加载中..." />
          </div>
        ) : filteredSettings.length === 0 ? (
          <Empty
            description={
              searchText
                ? '未找到匹配的设定'
                : '暂无设定，点击"新建设定"开始创建'
            }
            image={Empty.PRESENTED_IMAGE_SIMPLE}
          />
        ) : (
          <List
            grid={{ gutter: 16, xs: 1, sm: 2, md: 3 }}
            dataSource={filteredSettings}
            renderItem={(item) => (
              <List.Item>
                <Card
                  hoverable
                  size="small"
                  actions={[
                    <EditOutlined
                      key="edit"
                      onClick={() => handleEditSetting(item)}
                    />,
                    <DeleteOutlined
                      key="delete"
                      onClick={() => handleDeleteSetting(item)}
                      style={{ color: '#ff4d4f' }}
                    />,
                  ]}
                >
                  <Card.Meta
                    avatar={<SettingOutlined style={{ fontSize: 24, color: '#1890ff' }} />}
                    title={
                      <div>
                        {item.name}
                        {item.category && (
                          <Tag color="blue" style={{ marginLeft: 8, float: 'right' }}>
                            {item.category}
                          </Tag>
                        )}
                      </div>
                    }
                    description={
                      item.summary && (
                        <div
                          style={{
                            fontSize: 12,
                            color: '#666',
                            overflow: 'hidden',
                            textOverflow: 'ellipsis',
                            display: '-webkit-box',
                            WebkitLineClamp: 3,
                            WebkitBoxOrient: 'vertical',
                          }}
                        >
                          {item.summary}
                        </div>
                      )
                    }
                  />
                </Card>
              </List.Item>
            )}
          />
        )}
      </div>

      {/* 设定详情 Modal */}
      <SettingDetail
        visible={detailVisible}
        setting={selectedSetting}
        projectRoot={projectRoot}
        onClose={() => setDetailVisible(false)}
        onSaved={handleSettingSaved}
      />
    </div>
  )
}

export default SettingsPage

import { useState, useEffect } from 'react'
import { Layout, Menu, Button, message } from 'antd'
import {
  SaveOutlined,
  FolderOpenOutlined,
  BookOutlined,
  UserOutlined,
  SettingOutlined,
  ThunderboltOutlined,
  SearchOutlined,
} from '@ant-design/icons'
import OutlineTree from './OutlineTree'
import factsStore from '../db'
import Editor from './Editor'
import FactsPanel from './FactsPanel'
import AIToolsPanel from './AIToolsPanel'
import CharactersPage from '../pages/CharactersPage'
import SettingsPage from '../pages/SettingsPage'
import AppSettingsPage from '../pages/AppSettingsPage'
import ProjectManager from './ProjectManager'
import VectorSearchPanel from './VectorSearchPanel'
import type { MenuProps } from 'antd'

const { Sider, Content } = Layout

type TabKey = 'outline' | 'characters' | 'world' | 'facts' | 'search' | 'appSettings'

// 左侧菜单
const siderMenuItems: MenuProps['items'] = [
  { key: 'outline', icon: <BookOutlined />, label: '大纲导航' },
  { key: 'characters', icon: <UserOutlined />, label: '角色管理' },
  { key: 'world', icon: <SettingOutlined />, label: '世界设定' },
  { key: 'facts', icon: <ThunderboltOutlined />, label: '事实台账' },
  { key: 'search', icon: <SearchOutlined />, label: '语义检索' },
  { key: 'appSettings', icon: <SettingOutlined />, label: '应用设置' },
]

const Workbench = () => {
  const [activeTab, setActiveTab] = useState<TabKey>('outline')
  const [activeChapter, setActiveChapter] = useState<string | null>(null)
  const [chapterContent, setChapterContent] = useState('')
  const [projectRoot, setProjectRoot] = useState<string | null>(null)
  const [isDirty, setIsDirty] = useState(false)
  const [autoSaveTimer, setAutoSaveTimer] = useState<NodeJS.Timeout | null>(null)
  const [saveStatus, setSaveStatus] = useState<'idle' | 'saving' | 'saved' | 'error'>('idle')
  const [projectManagerVisible, setProjectManagerVisible] = useState(false)

  // 初始化项目
  useEffect(() => {
    const init = async () => {
      const root = await window.electronAPI.getProjectRoot()
      if (root) {
        setProjectRoot(root)
        factsStore.setProjectRoot(root)
      }
    }
    init()
  }, [])

  // 自动保存
  useEffect(() => {
    if (isDirty && activeChapter) {
      if (autoSaveTimer) clearTimeout(autoSaveTimer)

      const timer = setTimeout(() => {
        handleSave()
      }, 5000) // 5秒防抖自动保存

      setAutoSaveTimer(timer)
    }

    return () => {
      if (autoSaveTimer) clearTimeout(autoSaveTimer)
    }
  }, [chapterContent, isDirty])

  // 打开项目
  const handleOpenProject = () => {
    setProjectManagerVisible(true)
  }

  // 项目打开后的回调
  const handleProjectOpened = (projectPath: string) => {
    setProjectRoot(projectPath)
    factsStore.setProjectRoot(projectPath)
  }

  // 保存章节
  const handleSave = async () => {
    if (!activeChapter || !chapterContent) return

    setSaveStatus('saving')
    try {
      const result = await window.electronAPI.writeFile(activeChapter, chapterContent)
      if (result.success) {
        setIsDirty(false)
        setSaveStatus('saved')
        // 2秒后重置状态
        setTimeout(() => setSaveStatus('idle'), 2000)
      } else {
        setSaveStatus('error')
        message.error(`保存失败：${result.error}`)
        // 保存失败时立即重试一次
        setTimeout(async () => {
          setSaveStatus('saving')
          const retry = await window.electronAPI.writeFile(activeChapter, chapterContent)
          if (retry.success) {
            setIsDirty(false)
            setSaveStatus('saved')
            setTimeout(() => setSaveStatus('idle'), 2000)
          } else {
            setSaveStatus('error')
          }
        }, 1000)
      }
    } catch (error) {
      setSaveStatus('error')
      message.error('保存失败')
    }
  }

  // 章节选择
  const handleChapterSelect = async (filePath: string) => {
    if (isDirty) {
      // 提示保存
      const confirm = window.confirm('当前章节有未保存的内容，是否保存？')
      if (confirm) await handleSave()
    }

    setActiveChapter(filePath)

    // 读取章节内容
    try {
      const result = await window.electronAPI.readFile(filePath)
      if (result.success && result.content) {
        setChapterContent(result.content)
        setIsDirty(false)
      }
    } catch (error) {
      message.error('读取章节失败')
    }
  }

  // 内容变化
  const handleContentChange = (value: string | undefined) => {
    if (value === undefined) return
    setChapterContent(value)
    setIsDirty(true)
  }

  // 快捷键保存
  useEffect(() => {
    const handleKeyDown = (e: KeyboardEvent) => {
      if ((e.ctrlKey || e.metaKey) && e.key === 's') {
        e.preventDefault()
        handleSave()
      }
    }
    window.addEventListener('keydown', handleKeyDown)
    return () => window.removeEventListener('keydown', handleKeyDown)
  }, [activeChapter, chapterContent])

  return (
    <Layout style={{ height: '100vh' }}>
      {/* 顶部工具栏 */}
      <Layout.Header
        style={{
          display: 'flex',
          alignItems: 'center',
          padding: '0 20px',
          background: '#fff',
          borderBottom: '1px solid #e8e8e8',
          justifyContent: 'space-between'
        }}
      >
        <div style={{ display: 'flex', alignItems: 'center', gap: 20 }}>
          <h2 style={{ margin: 0 }}>🍅 番茄小说创作助手</h2>
          {projectRoot && <span style={{ color: '#999' }}>当前项目：{projectRoot}</span>}
        </div>
        <div style={{ display: 'flex', gap: 10 }}>
          <Button
            icon={<FolderOpenOutlined />}
            onClick={handleOpenProject}
          >
            打开项目
          </Button>
          <Button
            icon={<SaveOutlined />}
            type="primary"
            onClick={handleSave}
            disabled={saveStatus === 'saving' || !activeChapter}
            loading={saveStatus === 'saving'}
          >
            {saveStatus === 'saving'
              ? '保存中...'
              : saveStatus === 'saved'
                ? '已保存 ✓'
                : saveStatus === 'error'
                  ? '保存失败 ↺'
                  : isDirty
                    ? '保存 *'
                    : '已保存'}
          </Button>
        </div>
      </Layout.Header>

      <Layout>
        {/* 左侧边栏 */}
        <Sider width={64} theme="light">
          <Menu
            mode="inline"
            selectedKeys={[activeTab]}
            items={siderMenuItems}
            onClick={({ key }) => setActiveTab(key as TabKey)}
            style={{ height: '100%', borderRight: 0 }}
          />
        </Sider>

        {/* 左侧内容区 */}
        <Sider width={280} theme="light" style={{ borderRight: '1px solid #e8e8e8' }}>
          {activeTab === 'outline' && projectRoot && (
            <OutlineTree
              projectRoot={projectRoot}
              activeChapter={activeChapter}
              onSelect={handleChapterSelect}
            />
          )}
          {activeTab === 'characters' && (
            <CharactersPage
              projectRoot={projectRoot}
              onCharacterClick={(name) => {
                // 可选：切换到大纲并搜索该角色相关内容
              }}
            />
          )}
          {activeTab === 'world' && (
            <SettingsPage projectRoot={projectRoot} />
          )}
          {activeTab === 'facts' && <FactsPanel />}
          {activeTab === 'search' && (
            <VectorSearchPanel
              projectRoot={projectRoot}
              onJumpToChapter={(path) => {
                handleChapterSelect(path)
              }}
            />
          )}
          {activeTab === 'appSettings' && <AppSettingsPage />}
        </Sider>

        {/* 中间编辑区 */}
        <Content style={{ background: '#fff' }}>
          {activeChapter ? (
            <Editor
              value={chapterContent}
              onChange={handleContentChange}
              filePath={activeChapter}
            />
          ) : (
            <div
              style={{
                display: 'flex',
                height: '100%',
                alignItems: 'center',
                justifyContent: 'center',
                color: '#999',
                fontSize: 18,
              }}
            >
              请在左侧选择章节，或打开一个小说项目
            </div>
          )}
        </Content>

        {/* 右侧AI工具区 */}
        <Sider width={320} theme="light" style={{ borderLeft: '1px solid #e8e8e8' }}>
          <AIToolsPanel
            chapterContent={chapterContent}
            chapterPath={activeChapter}
            onInsertText={(text) => {
              // 支持 __REPLACE__ 标记：完全替换当前内容
              if (text.startsWith('__REPLACE__')) {
                const newContent = text.slice('__REPLACE__'.length)
                setChapterContent(newContent)
              } else {
                setChapterContent(prev => prev + text)
              }
              setIsDirty(true)
            }}
          />
        </Sider>
      </Layout>

      {/* 项目管理对话框 */}
      <ProjectManager
        visible={projectManagerVisible}
        onClose={() => setProjectManagerVisible(false)}
        onProjectOpened={handleProjectOpened}
      />
    </Layout>
  )
}

export default Workbench

/**
 * Facts 持久化层
 * 通过 IPC 调用主进程的 yamlService，读写 facts/*.yaml 文件
 * 与命令行工具共用同一数据源
 */

export interface Fact {
  id: string
  type: 'power' | 'item' | 'relation' | 'foreshadow'
  subject: string
  object: string
  content: string
  chapterStart: number
  chapterEnd: number
  createdAt: number
}

class FactsStore {
  private projectRoot: string | null = null

  async setProjectRoot(root: string): Promise<void> {
    this.projectRoot = root
  }

  private factsDir(): string {
    if (!this.projectRoot) throw new Error('未设置项目根路径')
    return `${this.projectRoot}/facts`
  }

  // ─── 读取 facts（通过 IPC 调用主进程 js-yaml） ─────────────────────────────

  async loadCharactersFacts(): Promise<Record<string, unknown>> {
    try {
      const result = await window.electronAPI.yaml.read(`${this.factsDir()}/characters_facts.yaml`)
      if (result.success && result.data) return result.data as Record<string, unknown>
    } catch {}
    return {}
  }

  async loadPlotFacts(): Promise<Record<string, unknown>> {
    try {
      const result = await window.electronAPI.yaml.read(`${this.factsDir()}/plot_facts.yaml`)
      if (result.success && result.data) return result.data as Record<string, unknown>
    } catch {}
    return {}
  }

  async loadSettingsFacts(): Promise<Record<string, unknown>> {
    try {
      const result = await window.electronAPI.yaml.read(`${this.factsDir()}/settings_facts.yaml`)
      if (result.success && result.data) return result.data as Record<string, unknown>
    } catch {}
    return {}
  }

  // ─── 写入 facts（通过 IPC 调用主进程 js-yaml） ─────────────────────────────

  async appendFacts(facts: Array<{
    type: string
    subject: string
    object?: string
    content: string
    chapterStart: number
    chapterEnd: number
    confidence: number
  }>): Promise<{ success: boolean; error?: string }> {
    try {
      if (!this.projectRoot) {
        return { success: false, error: '未设置项目根路径' }
      }

      const charFacts = (await this.loadCharactersFacts()) as Record<string, Record<string, unknown>>
      const plotFacts = (await this.loadPlotFacts()) as Record<string, unknown>

      for (const fact of facts) {
        if (fact.type === 'power' || fact.type === 'item' || fact.type === 'relation') {
          if (!charFacts[fact.subject]) {
            charFacts[fact.subject] = {}
          }
          const char: Record<string, unknown> = charFacts[fact.subject]

          if (fact.type === 'power' && fact.content) {
            const abilities = (char['abilities'] as string[]) || []
            if (!abilities.includes(fact.content)) {
              abilities.push(fact.content)
              char['abilities'] = abilities
            }
          }
          if (fact.type === 'relation' && fact.object) {
            const relationships = (char['relationships'] as Record<string, string>) || {}
            relationships[fact.object] = fact.content
            char['relationships'] = relationships
          }
          if (fact.type === 'item' && fact.content) {
            const traits = (char['personality_traits'] as string[]) || []
            if (!traits.includes(fact.content)) {
              traits.push(fact.content)
              char['personality_traits'] = traits
            }
          }
        }

        if (fact.type === 'foreshadow') {
          const foreshadowList = (plotFacts['伏笔清单'] as Array<Record<string, unknown>>) || []
          const existing = foreshadowList.some(
            p => p['description'] === fact.content && p['setup_chapter'] === fact.chapterStart
          )
          if (!existing) {
            foreshadowList.push({
              id: `F${Date.now()}-${Math.random().toString(36).slice(2, 6)}`,
              description: fact.content,
              setup_chapter: fact.chapterStart,
              status: '待回收',
              related_characters: fact.subject ? [fact.subject] : [],
            })
            plotFacts['伏笔清单'] = foreshadowList
          }
        }
      }

      await window.electronAPI.yaml.write(`${this.factsDir()}/characters_facts.yaml`, charFacts)
      await window.electronAPI.yaml.write(`${this.factsDir()}/plot_facts.yaml`, plotFacts)

      return { success: true }
    } catch (e: any) {
      return { success: false, error: e.message }
    }
  }

  // ─── 读取 facts 用于 UI 显示 ─────────────────────────────────────────────

  async getFacts(filters?: {
    type?: string
    subject?: string
    chapter?: number
  }): Promise<Fact[]> {
    try {
      const charFacts = await this.loadCharactersFacts() as Record<string, Record<string, unknown>>
      const plotFacts = await this.loadPlotFacts() as Record<string, unknown>

      const results: Fact[] = []

      // 从 characters_facts.yaml 还原 facts
      for (const [charName, char] of Object.entries(charFacts)) {
        if (char.abilities) {
          for (const ability of (char.abilities as string[]) || []) {
            results.push({
              id: `power-${charName}-${ability}`.slice(0, 64),
              type: 'power',
              subject: charName,
              object: '',
              content: ability,
              chapterStart: 1,
              chapterEnd: 9999,
              createdAt: 0,
            })
          }
        }
        if (char.relationships) {
          for (const [other, rel] of Object.entries(char.relationships as Record<string, string>)) {
            results.push({
              id: `rel-${charName}-${other}`.slice(0, 64),
              type: 'relation',
              subject: charName,
              object: other,
              content: rel,
              chapterStart: 1,
              chapterEnd: 9999,
              createdAt: 0,
            })
          }
        }
      }

      // 从 plot_facts.yaml 还原伏笔
      if (plotFacts['伏笔清单']) {
        for (const fb of (plotFacts['伏笔清单'] as Array<Record<string, unknown>>)) {
          results.push({
            id: `fb-${fb['id']}` || `fb-${Date.now()}`,
            type: 'foreshadow',
            subject: ((fb['related_characters'] as string[] || [])[0]) || '',
            object: '',
            content: String(fb['description'] || ''),
            chapterStart: Number(fb['setup_chapter'] || 1),
            chapterEnd: Number(fb['setup_chapter'] || 1),
            createdAt: 0,
          })
        }
      }

      // 过滤
      let filtered = results
      if (filters?.type && filters.type !== 'all') {
        filtered = filtered.filter(f => f.type === filters.type)
      }
      if (filters?.subject) {
        filtered = filtered.filter(
          f => f.subject === filters.subject || f.object === filters.subject
        )
      }
      if (filters?.chapter) {
        filtered = filtered.filter(
          f => f.chapterStart <= filters.chapter! && f.chapterEnd >= filters.chapter!
        )
      }

      return filtered
    } catch (e) {
      console.error('读取 facts 失败:', e)
      return []
    }
  }
}

