/**
 * 向量语义检索面板
 * 提供相似章节搜索功能
 *
 * 在 Electron 环境中，通过 IPC 调用 my-novel-tools 的 CLI 命令
 * 如果 CLI 不可用，则使用基于关键词的简单相似度搜索作为降级方案
 */

import { useState, useEffect } from 'react'
import {
  Input,
  Button,
  List,
  Card,
  Tag,
  Space,
  message,
  Alert,
  Spin,
  Tooltip,
  Modal,
} from 'antd'
import {
  SearchOutlined,
  BuildOutlined,
  CheckCircleOutlined,
  WarningOutlined,
} from '@ant-design/icons'

interface SearchResult {
  chapterPath: string
  chapterName: string
  similarity: number
  snippet: string
}

interface VectorSearchPanelProps {
  projectRoot: string | null
  onJumpToChapter?: (chapterPath: string) => void
}

const VectorSearchPanel: React.FC<VectorSearchPanelProps> = ({
  projectRoot,
  onJumpToChapter,
}) => {
  const [query, setQuery] = useState('')
  const [results, setResults] = useState<SearchResult[]>([])
  const [loading, setLoading] = useState(false)
  const [indexExists, setIndexExists] = useState<boolean | null>(null)
  const [cliAvailable, setCliAvailable] = useState<boolean | null>(null)

  // 检查向量索引是否存在
  const checkIndex = async () => {
    if (!projectRoot) return
    try {
      const indexFile = `${projectRoot}/data/vectors/index.json`
      const exists = await window.electronAPI.exists(indexFile)
      setIndexExists(exists)
    } catch {
      setIndexExists(false)
    }
  }

  useEffect(() => {
    checkIndex()
  }, [projectRoot])

  // 简单的关键词相似度搜索（降级方案）
  const simpleKeywordSearch = async (
    searchQuery: string,
    chapters: Array<{ path: string; name: string; content: string }>
  ): Promise<SearchResult[]> => {
    if (!searchQuery.trim()) return []

    const queryWords = searchQuery.toLowerCase().split(/\s+/).filter(Boolean)

    const scored = chapters.map(ch => {
      const content = ch.content.toLowerCase()
      let score = 0
      let matchedSnippet = ''

      // 计算关键词覆盖率
      const matchedWords = queryWords.filter(w => content.includes(w))
      score = matchedWords.length / queryWords.length

      // 找到匹配的片段
      const firstMatchIdx = content.indexOf(matchedWords[0] || queryWords[0])
      if (firstMatchIdx >= 0) {
        const start = Math.max(0, firstMatchIdx - 30)
        const end = Math.min(content.length, firstMatchIdx + 100)
        matchedSnippet = (start > 0 ? '...' : '') + ch.content.slice(start, end) + (end < content.length ? '...' : '')
      }

      return {
        chapterPath: ch.path,
        chapterName: ch.name,
        similarity: score,
        snippet: matchedSnippet || ch.content.slice(0, 100) + '...',
      }
    })

    return scored
      .filter(r => r.similarity > 0)
      .sort((a, b) => b.similarity - a.similarity)
      .slice(0, 10)
  }

  // 加载所有章节内容
  const loadAllChapters = async (): Promise<Array<{ path: string; name: string; content: string }>> => {
    if (!projectRoot) return []

    const chapters: Array<{ path: string; name: string; content: string }> = []

    const readDir = async (dirPath: string) => {
      try {
        const entries = await window.electronAPI.readdir(dirPath)
        for (const entry of entries) {
          const fullPath = `${dirPath}/${entry.name}`
          if (entry.isDirectory) {
            await readDir(fullPath)
          } else if (entry.isFile && entry.name.endsWith('.md')) {
            const contentResult = await window.electronAPI.readFile(fullPath)
            if (contentResult.success && contentResult.content) {
              chapters.push({
                path: fullPath,
                name: entry.name.replace('.md', ''),
                content: contentResult.content,
              })
            }
          }
        }
      } catch (e) {
        console.warn('读取目录失败:', dirPath, e)
      }
    }

    const plotsDir = `${projectRoot}/plots`
    const exists = await window.electronAPI.exists(plotsDir)
    if (exists) {
      await readDir(plotsDir)
    }

    return chapters
  }

  // 执行搜索
  const handleSearch = async () => {
    if (!query.trim()) {
      message.warning('请输入搜索内容')
      return
    }
    if (!projectRoot) {
      message.warning('请先打开项目')
      return
    }

    setLoading(true)
    setResults([])

    try {
      // 如果有向量索引，优先使用（通过 CLI 工具）
      if (indexExists) {
        // 由于浏览器无法直接运行 Node.js CLI，这里使用降级方案
        // 在实际 Electron 环境中，可以通过 IPC 调用主进程执行 CLI
        message.info('使用增强检索模式...')
      }

      // 使用关键词搜索作为降级方案
      const chapters = await loadAllChapters()
      const searchResults = await simpleKeywordSearch(query, chapters)
      setResults(searchResults)

      if (searchResults.length === 0) {
        message.info('未找到相关内容，尝试其他关键词')
      }
    } catch (error) {
      console.error('搜索失败:', error)
      message.error('搜索失败')
    } finally {
      setLoading(false)
    }
  }

  // 构建向量索引（提示用户使用 CLI）
  const handleBuildIndex = () => {
    Modal.info({
      title: '📦 构建向量索引',
      content: (
        <div>
          <p>向量索引构建需要在命令行中执行：</p>
          <pre
            style={{
              background: '#f5f5f5',
              padding: 12,
              borderRadius: 4,
              fontFamily: 'monospace',
              fontSize: 13,
            }}
          >{`cd my-novel-tools
node bin/build-vector-index.js -p ../your-project-path`}</pre>
          <p style={{ color: '#666', fontSize: 12 }}>
            首次运行会自动下载向量模型（约 130MB），请耐心等待。
          </p>
        </div>
      ),
      okText: '知道了',
      width: 500,
    })
  }

  if (!projectRoot) {
    return (
      <div style={{ padding: 40, textAlign: 'center', color: '#999' }}>
        请先打开一个小说项目
      </div>
    )
  }

  return (
    <div style={{ height: '100%', display: 'flex', flexDirection: 'column' }}>
      {/* 头部 */}
      <div style={{ padding: '12px 16px', borderBottom: '1px solid #e8e8e8' }}>
        <div style={{ marginBottom: 10 }}>
          <span style={{ fontSize: 13, fontWeight: 500 }}>🔍 相似章节检索</span>
        </div>

        {/* 索引状态 */}
        <div style={{ marginBottom: 10, fontSize: 12 }}>
          {indexExists ? (
            <Tag color="green" icon={<CheckCircleOutlined />}>
              向量索引已就绪
            </Tag>
          ) : (
            <Tag color="orange" icon={<WarningOutlined />}>
              未构建向量索引
            </Tag>
          )}
          <Button
            size="small"
            icon={<BuildOutlined />}
            onClick={handleBuildIndex}
            style={{ marginLeft: 8 }}
          >
            构建索引
          </Button>
        </div>

        {/* 搜索框 */}
        <Space direction="vertical" style={{ width: '100%' }}>
          <Input.Search
            placeholder="输入情节描述，查找相似章节..."
            value={query}
            onChange={(e) => setQuery(e.target.value)}
            onSearch={handleSearch}
            loading={loading}
            enterButton={
              <Button type="primary" icon={<SearchOutlined />}>
                搜索
              </Button>
            }
          />
        </Space>

        {!indexExists && (
          <Alert
            message="当前使用关键词匹配检索。构建向量索引后支持语义检索，效果更佳。"
            type="info"
            showIcon
            style={{ marginTop: 8, fontSize: 11 }}
          />
        )}
      </div>

      {/* 结果列表 */}
      <div style={{ flex: 1, overflow: 'auto', padding: 16 }}>
        {loading ? (
          <div style={{ textAlign: 'center', padding: 40 }}>
            <Spin tip="搜索中..." />
          </div>
        ) : results.length === 0 ? (
          <div style={{ color: '#999', textAlign: 'center', padding: 40, fontSize: 13 }}>
            {query ? '未找到相似章节' : '输入内容开始搜索'}
          </div>
        ) : (
          <List
            dataSource={results}
            renderItem={(item) => (
              <List.Item
                style={{ cursor: 'pointer' }}
                onClick={() => onJumpToChapter?.(item.chapterPath)}
              >
                <List.Item.Meta
                  title={
                    <Space>
                      <span>{item.chapterName}</span>
                      <Tag color="blue">
                        相似度 {Math.round(item.similarity * 100)}%
                      </Tag>
                    </Space>
                  }
                  description={
                    <div
                      style={{
                        fontSize: 12,
                        color: '#666',
                        overflow: 'hidden',
                        textOverflow: 'ellipsis',
                        display: '-webkit-box',
                        WebkitLineClamp: 2,
                        WebkitBoxOrient: 'vertical',
                      }}
                    >
                      {item.snippet}
                    </div>
                  }
                />
              </List.Item>
            )}
          />
        )}
      </div>
    </div>
  )
}

export default VectorSearchPanel

/**
 * AI 服务 - 主进程 IPC 处理器
 * 处理渲染进程发来的 AI 相关 IPC 调用
 */

import { IpcMain, BrowserWindow } from 'electron'
import axios, { AxiosError } from 'axios'
import fs from 'node:fs'
import path from 'node:path'
import os from 'node:os'
import { app } from 'electron'

// ─── 配置路径 ────────────────────────────────────────────────────────────────

function getSettingsPath(): string {
  return path.join(app.getPath('userData'), 'ai-settings.json')
}

// ─── 配置读写 ────────────────────────────────────────────────────────────────

interface AiSettings {
  deepseekApiKey?: string
  doubaoApiKey?: string
  [key: string]: string | undefined
}

function loadSettings(): AiSettings {
  const p = getSettingsPath()
  if (fs.existsSync(p)) {
    try {
      return JSON.parse(fs.readFileSync(p, 'utf-8'))
    } catch {
      return {}
    }
  }
  return {}
}

function saveSettings(settings: AiSettings): void {
  const p = getSettingsPath()
  fs.mkdirSync(path.dirname(p), { recursive: true })
  fs.writeFileSync(p, JSON.stringify(settings, null, 2), 'utf-8')
}

// ─── API 调用 ────────────────────────────────────────────────────────────────

interface CallOptions {
  model?: string
  systemPrompt?: string
  temperature?: number
  maxTokens?: number
  topP?: number
  presencePenalty?: number
  frequencyPenalty?: number
}

async function callAI(
  prompt: string,
  options: CallOptions = {}
): Promise<{ success: boolean; content?: string; reasoning?: string; error?: string }> {
  const { model = 'deepseek', systemPrompt, temperature = 0.7, maxTokens = 2000 } = options

  const apiKey = loadSettings()[`${model}ApiKey`]
    || process.env.DEEPSEEK_API_KEY
    || process.env.DOUBAO_API_KEY

  if (!apiKey) {
    return {
      success: false,
      error: `未配置 API Key。请先在设置中配置 ${model} 的 API Key。`,
    }
  }

  try {
    const isDeepSeek = model === 'deepseek' || model === 'deepseek-chat' || model === 'deepseek-reasoner'
    if (isDeepSeek) {
      const deepseekModel = model === 'deepseek-reasoner' ? 'deepseek-reasoner' : 'deepseek-chat'
      const response = await axios.post(
        'https://api.deepseek.com/v1/chat/completions',
        {
          model: deepseekModel,
          messages: [
            ...(systemPrompt ? [{ role: 'system', content: systemPrompt }] : []),
            { role: 'user', content: prompt },
          ],
          temperature,
          max_tokens: maxTokens,
        },
        {
          headers: {
            Authorization: `Bearer ${apiKey}`,
            'Content-Type': 'application/json',
          },
          timeout: 60000,
        }
      )
      return { success: true, content: response.data.choices[0]?.message?.content || '' }
    }

    if (model === 'doubao-pro' || model === 'doubao-lite' || model === 'doubao-mini') {
      const endpoint = model === 'doubao-pro'
        ? 'https://ark.cn-beijing.volces.com/api/v3/chat/completions'
        : 'https://ark.cn-beijing.volces.com/api/v3/chat/completions'

      const doubaoModel = model === 'doubao-pro'
        ? 'doubao-pro-32k'
        : model === 'doubao-lite'
          ? 'doubao-lite-32k'
          : 'doubao-mini'

      const response = await axios.post(
        endpoint,
        {
          model: doubaoModel,
          messages: [
            ...(systemPrompt ? [{ role: 'system', content: systemPrompt }] : []),
            { role: 'user', content: prompt },
          ],
          temperature,
          max_tokens: maxTokens,
        },
        {
          headers: {
            Authorization: `Bearer ${apiKey}`,
            'Content-Type': 'application/json',
          },
          timeout: 60000,
        }
      )
      return { success: true, content: response.data.choices[0]?.message?.content || '' }
    }

    return { success: false, error: `不支持的模型: ${model}` }
  } catch (err) {
    const axiosErr = err as AxiosError
    if (axiosErr.response) {
      return { success: false, error: `API 错误 ${axiosErr.response.status}: ${JSON.stringify(axiosErr.response.data)}` }
    }
    return { success: false, error: `请求失败: ${axiosErr.message}` }
  }
}

async function streamAI(
  prompt: string,
  options: CallOptions,
  sendChunk: (content: string, done: boolean, reasoning?: string) => void,
  sendError: (error: string) => void
): Promise<void> {
  const { model = 'deepseek', systemPrompt, temperature = 0.7, maxTokens = 2000 } = options

  const apiKey = loadSettings()[`${model}ApiKey`]
    || process.env.DEEPSEEK_API_KEY
    || process.env.DOUBAO_API_KEY

  if (!apiKey) {
    sendError(`未配置 API Key。请先在设置中配置 ${model} 的 API Key。`)
    sendChunk('', true)
    return
  }

  try {
    const isDeepSeek = model === 'deepseek' || model === 'deepseek-chat' || model === 'deepseek-reasoner'
    const headers: Record<string, string> = {
      'Content-Type': 'application/json',
      Authorization: `Bearer ${apiKey}`,
    }

    const body: Record<string, unknown> = {
      model: isDeepSeek
        ? (model === 'deepseek-reasoner' ? 'deepseek-reasoner' : 'deepseek-chat')
        : 'doubao-pro-32k',
      messages: [
        ...(systemPrompt ? [{ role: 'system', content: systemPrompt }] : []),
        { role: 'user', content: prompt },
      ],
      temperature,
      max_tokens: maxTokens,
    }

    // DeepSeek 支持流式
    if (isDeepSeek) {
      body.stream = true

      const response = await axios.post(
        'https://api.deepseek.com/v1/chat/completions',
        body,
        {
          headers,
          responseType: 'stream',
          timeout: 120000,
        }
      )

      const stream = response.data as import('node:stream').Stream
      let buffer = ''

      await new Promise<void>((resolve, reject) => {
        stream.on('data', (chunk: Buffer) => {
          buffer += chunk.toString()
          const lines = buffer.split('\n')
          buffer = lines.pop() || ''

          for (const line of lines) {
            const trimmed = line.trim()
            if (!trimmed || trimmed === 'data: [DONE]') continue
            if (!trimmed.startsWith('data: ')) continue
            const data = trimmed.slice(6)
            try {
              const parsed = JSON.parse(data)
              const content = parsed.choices?.[0]?.delta?.content || ''
              const reasoning = parsed.choices?.[0]?.delta?.reasoning || ''
              if (content || reasoning) {
                sendChunk(content, false, reasoning)
              }
            } catch {}
          }
        })

        stream.on('end', () => {
          if (buffer.trim() && buffer.trim() !== '[DONE]') {
            try {
              const data = JSON.parse(buffer.slice(6))
              const content = data.choices?.[0]?.delta?.content || ''
              if (content) sendChunk(content, false)
            } catch {}
          }
          sendChunk('', true)
          resolve()
        })

        stream.on('error', (err: Error) => {
          sendError(err.message)
          sendChunk('', true)
          resolve()
        })
      })
    } else {
      // 非流式降级
      const result = await callAI(prompt, options)
      if (result.success) {
        sendChunk(result.content || '', false)
        sendChunk('', true)
      } else {
        sendError(result.error || '未知错误')
        sendChunk('', true)
      }
    }
  } catch (err) {
    const axiosErr = err as AxiosError
    sendError(axiosErr.message || '请求失败')
    sendChunk('', true)
  }
}

// ─── IPC 处理器 ──────────────────────────────────────────────────────────────

export function setupAiHandlers(ipcMain: IpcMain): void {
  // 保存 API Key
  ipcMain.handle('ai:saveApiKey', async (_event, service: string, apiKey: string) => {
    try {
      const settings = loadSettings()
      settings[`${service}ApiKey`] = apiKey
      saveSettings(settings)
      return { success: true }
    } catch (e: any) {
      return { success: false, error: e.message }
    }
  })

  // 检查是否已配置
  ipcMain.handle('ai:isConfigured', async (_event, service: string) => {
    const settings = loadSettings()
    const configured = !!(settings[`${service}ApiKey`] || process.env[`${service.toUpperCase()}_API_KEY`])
    return { success: true, configured }
  })

  // 获取已配置的服务列表
  ipcMain.handle('ai:getConfiguredServices', async () => {
    const settings = loadSettings()
    const services: string[] = []
    if (settings.deepseekApiKey || process.env.DEEPSEEK_API_KEY) services.push('deepseek')
    if (settings.doubaoApiKey || process.env.DOUBAO_API_KEY) services.push('doubao')
    return { success: true, services }
  })

  // AI 调用（非流式）
  ipcMain.handle('ai:call', async (_event, prompt: string, options?: CallOptions) => {
    return callAI(prompt, options || {})
  })

  // AI 流式调用
  ipcMain.handle('ai:stream', async (event, prompt: string, options?: CallOptions) => {
    const win = BrowserWindow.fromWebContents(event.sender)
    if (!win || win.isDestroyed()) return { success: false, error: '窗口已关闭' }

    await streamAI(
      prompt,
      options || {},
      (content, done, reasoning) => {
        if (!win.isDestroyed()) {
          win.webContents.send('ai:stream-chunk', { content, done, reasoning })
        }
      },
      (error) => {
        if (!win.isDestroyed()) {
          win.webContents.send('ai:stream-error', error)
        }
      }
    )

    return { success: true }
  })

  // 测试连接
  ipcMain.handle('ai:testConnection', async (_event, service: string) => {
    const testPrompt = '请回复"连接成功"，不需要其他内容。'
    const result = await callAI(testPrompt, { model: service, maxTokens: 50 })
    return { success: result.success, result: result.success, error: result.error }
  })

  // 保存设置
  ipcMain.handle('ai:saveSetting', async (_event, key: string, value: any) => {
    try {
      const settings = loadSettings()
      settings[key] = value
      saveSettings(settings)
      return { success: true }
    } catch (e: any) {
      return { success: false, error: e.message }
    }
  })

  // 读取设置
  ipcMain.handle('ai:getSetting', async (_event, key: string, defaultValue?: any) => {
    const settings = loadSettings()
    return { success: true, value: settings[key] ?? defaultValue }
  })
}

import { useState, useEffect } from 'react'
import { Tree, Spin, Empty, message } from 'antd'
import { FileOutlined, FolderOutlined } from '@ant-design/icons'
import type { DataNode } from 'antd/es/tree'

// 浏览器环境下替代 path.join 的工具函数
const pathJoin = (...parts: string[]): string => {
  return parts.filter(Boolean).join('/')
}

interface OutlineTreeProps {
  projectRoot: string
  activeChapter: string | null
  onSelect: (filePath: string) => void
}

interface FileEntry {
  name: string
  isDirectory: boolean
  isFile: boolean
  path: string
  children?: FileEntry[]
}

const OutlineTree = ({ projectRoot, activeChapter, onSelect }: OutlineTreeProps) => {
  const [treeData, setTreeData] = useState<DataNode[]>([])
  const [loading, setLoading] = useState(false)
  const [expandedKeys, setExpandedKeys] = useState<React.Key[]>([])

  // 读取目录结构
  const loadDirectory = async (dirPath: string): Promise<FileEntry[]> => {
    try {
      const entries = await window.electronAPI.readdir(dirPath)
      if (!Array.isArray(entries)) return []

      const result: FileEntry[] = []

      for (const entry of entries) {
        const fullPath = pathJoin(dirPath, entry.name)

        if (entry.isDirectory) {
          const children = await loadDirectory(fullPath)
          result.push({
            name: entry.name,
            isDirectory: true,
            isFile: false,
            path: fullPath,
            children
          })
        } else if (entry.isFile && entry.name.endsWith('.md')) {
          result.push({
            name: entry.name.replace('.md', ''),
            isDirectory: false,
            isFile: true,
            path: fullPath
          })
        }
      }

      return result.sort((a, b) => {
        if (a.isDirectory && !b.isDirectory) return -1
        if (!a.isDirectory && b.isDirectory) return 1
        return a.name.localeCompare(b.name)
      })
    } catch (error) {
      console.error('读取目录失败:', error)
      return []
    }
  }

  // 转换为 Ant Design Tree 需要的格式
  const convertToTreeData = (entries: FileEntry[], parentKey: string = ''): DataNode[] => {
    return entries.map((entry, index) => {
      const key = parentKey ? `${parentKey}-${index}` : `${index}`

      if (entry.isDirectory && entry.children) {
        return {
          title: entry.name,
          key,
          icon: <FolderOutlined />,
          children: convertToTreeData(entry.children, key),
          isLeaf: false
        }
      } else {
        return {
          title: entry.name,
          key: entry.path,
          icon: <FileOutlined />,
          isLeaf: true
        }
      }
    })
  }

  // 加载大纲
  useEffect(() => {
    const loadOutline = async () => {
      if (!projectRoot) return

      setLoading(true)
      try {
        const plotsDir = pathJoin(projectRoot, 'plots')
        const exists = await window.electronAPI.exists(plotsDir)
        if (!exists) {
          await window.electronAPI.mkdir(plotsDir)
          setTreeData([])
          return
        }

        const entries = await loadDirectory(plotsDir)
        const data = convertToTreeData(entries)
        setTreeData(data)

        const getAllKeys = (nodes: DataNode[]): string[] => {
          let keys: string[] = []
          nodes.forEach(node => {
            keys.push(node.key as string)
            if (node.children) keys = keys.concat(getAllKeys(node.children))
          })
          return keys
        }
        setExpandedKeys(getAllKeys(data))
      } catch (error) {
        message.error('加载大纲失败')
        console.error(error)
      } finally {
        setLoading(false)
      }
    }

    loadOutline()
  }, [projectRoot])

  // 监听文件变化，自动刷新大纲
  useEffect(() => {
    if (!projectRoot) return

    const plotsDir = pathJoin(projectRoot, 'plots')
    window.electronAPI.fsWatch(plotsDir)

    const removeListener = window.electronAPI.onFsChange(() => {
      loadDirectory(pathJoin(projectRoot, 'plots')).then(entries => {
        const data = convertToTreeData(entries)
        setTreeData(data)
      })
    })

    return () => {
      removeListener()
      window.electronAPI.fsUnwatch()
    }
  }, [projectRoot])

  // 处理选择
  const handleSelect = (selectedKeys: React.Key[]) => {
    if (selectedKeys.length === 0) return
    const key = String(selectedKeys[0])
    if (key.startsWith('/') || key.includes('.md')) {
      onSelect(key)
    }
  }

  if (loading) {
    return (
      <div style={{ padding: 20, textAlign: 'center' }}>
        <Spin tip="加载中..." />
      </div>
    )
  }

  if (treeData.length === 0) {
    return (
      <div style={{ padding: 20 }}>
        <Empty
          description="暂无章节"
          image={Empty.PRESENTED_IMAGE_SIMPLE}
        />
      </div>
    )
  }

  return (
    <div style={{ height: '100%', overflow: 'auto', padding: 10 }}>
      <Tree
        treeData={treeData}
        expandedKeys={expandedKeys}
        selectedKeys={activeChapter ? [activeChapter] : []}
        onSelect={handleSelect}
        onExpand={setExpandedKeys}
        showIcon
        defaultExpandAll
      />
    </div>
  )
}

export default OutlineTree

/**
 * 应用设置页面
 * API密钥管理、模型选择、温度参数、主题切换、自动保存间隔
 */

import { useState, useEffect } from 'react'
import {
  Card,
  Form,
  Input,
  Select,
  Slider,
  Switch,
  Button,
  Space,
  Divider,
  message,
  Alert,
  Tabs,
  Tag,
  Tooltip,
  InputNumber,
  List,
  Modal,
} from 'antd'
import {
  KeyOutlined,
  SaveOutlined,
  CheckCircleOutlined,
  CloseCircleOutlined,
  ApiOutlined,
  SettingOutlined,
  ExperimentOutlined,
} from '@ant-design/icons'

// 可用的 AI 服务
const AI_SERVICES = [
  { value: 'deepseek', label: 'DeepSeek', models: ['deepseek-chat', 'deepseek-reasoner'] },
  { value: 'doubao', label: '豆包 (Doubao)', models: ['doubao-pro', 'doubao-lite', 'doubao-mini'] },
]

// 主题选项
const THEME_OPTIONS = [
  { value: 'light', label: '浅色' },
  { value: 'dark', label: '深色' },
  { value: 'system', label: '跟随系统' },
]

interface AppSettings {
  // AI 设置
  aiServices: Record<string, { apiKey: string; model: string; temperature: number; enabled: boolean }>
  // 自动保存
  autoSaveInterval: number // 秒
  autoSaveEnabled: boolean
  // 外观
  theme: string
  editorFontSize: number
  editorLineHeight: number
}

const DEFAULT_SETTINGS: AppSettings = {
  aiServices: {
    deepseek: { apiKey: '', model: 'deepseek-chat', temperature: 0.7, enabled: true },
    doubao: { apiKey: '', model: 'doubao-pro', temperature: 0.8, enabled: false },
  },
  autoSaveInterval: 5,
  autoSaveEnabled: true,
  theme: 'light',
  editorFontSize: 16,
  editorLineHeight: 1.8,
}

const AppSettingsPage: React.FC = () => {
  const [form] = Form.useForm<AppSettings>()
  const [saving, setSaving] = useState(false)
  const [testingService, setTestingService] = useState<string | null>(null)
  const [testResult, setTestResult] = useState<Record<string, boolean>>({})

  // 加载设置
  const loadSettings = async () => {
    try {
      const result = await window.electronAPI.ai.getSetting('appSettings', DEFAULT_SETTINGS)
      if (result.success && result.value) {
        form.setFieldsValue(result.value as AppSettings)
      } else {
        form.setFieldsValue(DEFAULT_SETTINGS)
      }
    } catch (error) {
      form.setFieldsValue(DEFAULT_SETTINGS)
    }
  }

  useEffect(() => {
    loadSettings()
  }, [])

  // 保存设置
  const handleSave = async () => {
    try {
      const values = form.getFieldsValue()
      setSaving(true)

      // 检查是否有 API key 需要加密保存
      for (const [service, config] of Object.entries(values.aiServices || {})) {
        if (config.apiKey && !config.apiKey.startsWith('encrypted:')) {
          // 加密保存
          try {
            // eslint-disable-next-line @typescript-eslint/no-explicit-any
            const encFn = window.electronAPI.safeStorage.encrypt as (text: string) => Promise<{ success: boolean; data?: Uint8Array; error?: string }>
            const encResult = await encFn(config.apiKey)
            if (encResult.success && encResult.data) {
              // 将 Uint8Array 转为 base64 字符串存储
              const base64 = btoa(String.fromCharCode(...encResult.data))
              values.aiServices[service].apiKey = `encrypted:${base64}`
            }
          } catch (e) {
            console.warn('API key 加密失败，将以明文保存（不推荐）:', e)
          }
        }
      }

      await window.electronAPI.ai.saveSetting('appSettings', values)
      message.success('设置已保存')
    } catch (error) {
      message.error('保存失败')
    } finally {
      setSaving(false)
    }
  }

  // 测试连接
  const handleTestConnection = async (service: string) => {
    setTestingService(service)
    setTestResult(prev => ({ ...prev, [service]: false }))
    try {
      const result = await window.electronAPI.ai.testConnection(service)
      setTestResult(prev => ({ ...prev, [service]: !!(result.success && result.result) }))
      if (result.success && result.result) {
        message.success(`${service} 连接成功`)
      } else {
        message.error(`${service} 连接失败: ${result.error}`)
      }
    } catch (error) {
      setTestResult(prev => ({ ...prev, [service]: false }))
      message.error(`${service} 连接失败`)
    } finally {
      setTestingService(null)
    }
  }

  // 验证 API Key 格式（解密显示）
  const getDisplayApiKey = (apiKey: string) => {
    if (!apiKey) return ''
    if (apiKey.startsWith('encrypted:')) {
      return '••••••••（已加密）'
    }
    if (apiKey.length > 8) {
      return apiKey.slice(0, 4) + '••••••••' + apiKey.slice(-4)
    }
    return apiKey
  }

  const values = form.getFieldsValue()

  return (
    <div
      style={{
        maxWidth: 800,
        margin: '0 auto',
        padding: 24,
        overflow: 'auto',
        height: '100%',
      }}
    >
      <div
        style={{
          display: 'flex',
          justifyContent: 'space-between',
          alignItems: 'center',
          marginBottom: 24,
        }}
      >
        <h2 style={{ margin: 0 }}>⚙️ 应用设置</h2>
        <Button
          type="primary"
          icon={<SaveOutlined />}
          loading={saving}
          onClick={handleSave}
        >
          保存设置
        </Button>
      </div>

      <Form
        form={form}
        layout="vertical"
        initialValues={DEFAULT_SETTINGS}
      >
        <Tabs
          items={[
            {
              key: 'ai',
              label: <span><ApiOutlined /> AI 服务</span>,
              children: (
                <div>
                  {AI_SERVICES.map(service => (
                    <Card
                      key={service.value}
                      size="small"
                      title={
                        <Space>
                          {service.label}
                          <Tag color={values.aiServices?.[service.value]?.enabled ? 'green' : 'default'}>
                            {values.aiServices?.[service.value]?.enabled ? '已启用' : '未启用'}
                          </Tag>
                        </Space>
                      }
                      style={{ marginBottom: 16 }}
                      extra={
                        <Switch
                          checked={values.aiServices?.[service.value]?.enabled}
                          onChange={(checked) => {
                            form.setFieldsValue({
                              ['aiServices']: {
                                [service.value]: {
                                  enabled: checked,
                                },
                              },
                            })
                          }}
                        />
                      }
                    >
                      <Form.Item
                        label="API Key"
                        name={['aiServices', service.value, 'apiKey']}
                        extra={
                          values.aiServices?.[service.value]?.apiKey && (
                            <Tag style={{ marginTop: 4 }}>
                              {getDisplayApiKey(values.aiServices?.[service.value]?.apiKey || '')}
                            </Tag>
                          )
                        }
                      >
                        <Input.Password
                          placeholder={
                            service.value === 'deepseek'
                              ? 'sk-xxxxxxxxxxxxxxxx'
                              : '输入 API Key'
                          }
                        />
                      </Form.Item>

                      <Form.Item
                        label="模型"
                        name={['aiServices', service.value, 'model']}
                      >
                        <Select
                          options={service.models.map(m => ({ value: m, label: m }))}
                          style={{ width: 200 }}
                        />
                      </Form.Item>

                      <Form.Item
                        label={
                          <Tooltip title="Temperature 控制创造性：0.0-0.3 更确定性，0.7-1.0 更有创意">
                            Temperature（创造性）
                          </Tooltip>
                        }
                        name={['aiServices', service.value, 'temperature']}
                      >
                        <Slider
                          min={0}
                          max={1}
                          step={0.1}
                          marks={{
                            0: '精准',
                            0.5: '平衡',
                            1: '创意',
                          }}
                          style={{ width: 300 }}
                        />
                      </Form.Item>

                      <Button
                        size="small"
                        icon={
                          testResult[service.value] ? (
                            <CheckCircleOutlined style={{ color: '#52c41a' }} />
                          ) : testResult[service.value] === false ? (
                            <CloseCircleOutlined style={{ color: '#ff4d4f' }} />
                          ) : undefined
                        }
                        onClick={() => handleTestConnection(service.value)}
                        loading={testingService === service.value}
                      >
                        测试连接
                      </Button>
                    </Card>
                  ))}

                  <Alert
                    message="API Key 安全说明"
                    description="API Key 将使用系统安全存储（SafeStorage）加密保存，不会以明文形式存储在配置文件中。"
                    type="info"
                    showIcon
                  />
                </div>
              ),
            },
            {
              key: 'editor',
              label: <span><ExperimentOutlined /> 编辑器</span>,
              children: (
                <div>
                  <Card size="small" title="自动保存" style={{ marginBottom: 16 }}>
                    <Form.Item
                      label="启用自动保存"
                      name="autoSaveEnabled"
                      valuePropName="checked"
                    >
                      <Switch />
                    </Form.Item>

                    <Form.Item
                      label="自动保存间隔（秒）"
                      name="autoSaveInterval"
                    >
                      <Slider
                        min={1}
                        max={30}
                        marks={{ 3: '3秒', 5: '5秒', 10: '10秒', 30: '30秒' }}
                        disabled={!values.autoSaveEnabled}
                      />
                    </Form.Item>
                  </Card>

                  <Card size="small" title="编辑器外观">
                    <Form.Item
                      label="字体大小"
                      name="editorFontSize"
                    >
                      <Slider
                        min={12}
                        max={24}
                        marks={{ 14: '14', 16: '16', 18: '18', 20: '20' }}
                      />
                    </Form.Item>

                    <Form.Item
                      label="行高"
                      name="editorLineHeight"
                    >
                      <Slider
                        min={1.2}
                        max={2.5}
                        step={0.1}
                        marks={{ 1.6: '1.6', 1.8: '1.8', 2.0: '2.0' }}
                      />
                    </Form.Item>
                  </Card>
                </div>
              ),
            },
            {
              key: 'appearance',
              label: <span><SettingOutlined /> 外观</span>,
              children: (
                <Card size="small" title="主题设置">
                  <Form.Item
                    label="主题"
                    name="theme"
                  >
                    <Select options={THEME_OPTIONS} style={{ width: 200 }} />
                  </Form.Item>

                  <Alert
                    message="深色主题切换需要重启应用生效"
                    type="warning"
                    showIcon
                    style={{ marginTop: 8 }}
                  />
                </Card>
              ),
            },
          ]}
        />
      </Form>
    </div>
  )
}

export default AppSettingsPage

